export default "<template>\r\n\r\n    <FlowDesignerLayout\r\n        class=\"flow-designer-test\"\r\n        ref=\"layoutRef\"\r\n        :mode=\"currentMode\"\r\n        :permission-config=\"permissionConfig\"\r\n        @ready=\"handleReady\"\r\n        @save=\"handleSave\"\r\n        @error=\"handleError\"\r\n        @mode-change=\"handleModeChange\"\r\n        :before-node-add=\"handleBeforeNodeAdd\"\r\n        :after-node-add=\"handleAfterNodeAdd\"\r\n        :before-node-remove=\"handleBeforeNodeRemove\"\r\n        :before-edge-add=\"handleBeforeEdgeAdd\"\r\n        :after-edge-add=\"handleAfterEdgeAdd\"\r\n        :before-edge-remove=\"handleBeforeEdgeRemove\"\r\n        :after-edge-remove=\"handleAfterEdgeRemove\"\r\n        :after-data-loaded=\"handleAfterDataLoaded\"\r\n        :before-node-select=\"handleBeforeNodeSelect\"\r\n        :before-edge-select=\"handleBeforeEdgeSelect\"\r\n        :before-edge-hover=\"handleBeforeEdgeHover\"\r\n        :canvasConfig=\"{ //此处画布配置，格式参考defaultConfig.ts, 传入后会与defaultConfig.ts进行merge, 传入的优先级会更高覆盖掉defaultConfig\r\n      grid: {\r\n        //type: 'mesh'\r\n      },\r\n      tooltip: {\r\n        //offsetX: -10,  // 向左偏移 15px\r\n        //offsetY: -10,  // 向上偏移 10px\r\n      },\r\n      // highlight: {\r\n      //   nodeHoverOutEdgeFlow: {\r\n      //     disableWhenNodeCountExceeds: 50\r\n      //   }\r\n      // }\r\n    }\"\r\n    >\r\n      <!-- 顶部工具栏 -->\r\n      <template #toolbar=\"scope\">\r\n        <Toolbar\r\n            :zoom-percent=\"scope.zoomPercent\"\r\n            :has-selection=\"scope.hasSelection\"\r\n            :can-paste=\"scope.canPaste\"\r\n            :can-group=\"scope.canGroup\"\r\n            :can-ungroup=\"scope.canUngroup\"\r\n            :can-undo=\"scope.canUndo\"\r\n            :can-redo=\"scope.canRedo\"\r\n            :designer-mode=\"scope.currentMode\"\r\n            @undo=\"scope.onUndo\"\r\n            @redo=\"scope.onRedo\"\r\n            @zoom-in=\"scope.onZoomIn\"\r\n            @zoom-out=\"scope.onZoomOut\"\r\n            @zoom-to=\"scope.onZoomTo\"\r\n            @fit-view=\"scope.onFitView\"\r\n            @reset-view=\"scope.onResetView\"\r\n            @copy=\"scope.onCopy\"\r\n            @paste=\"scope.onPaste\"\r\n            @to-front=\"scope.onToFront\"\r\n            @to-back=\"scope.onToBack\"\r\n            @align-left=\"scope.onAlignLeft\"\r\n            @align-right=\"scope.onAlignRight\"\r\n            @align-top=\"scope.onAlignTop\"\r\n            @align-bottom=\"scope.onAlignBottom\"\r\n            @group=\"scope.onGroup\"\r\n            @ungroup=\"scope.onUngroup\"\r\n            @export=\"scope.onExport\"\r\n            @import=\"scope.onImport\"\r\n            @open-settings=\"scope.onOpenSettings\"\r\n            @mode-change=\"scope.onModeChange\"\r\n        />\r\n      </template>\r\n\r\n      <!-- 左侧节点面板 -->\r\n      <template #palette=\"scope\">\r\n        <NodePalette @start-drag=\"scope.onStartDrag\" />\r\n      </template>\r\n\r\n      <!-- 右侧属性面板 -->\r\n      <template #properties>\r\n        <PropertiesPanel />\r\n      </template>\r\n\r\n      <!-- 【测试】节点搜索框：纯插槽，完全自定义 UI -->\r\n      <template #search-box=\"{ keyword, total, currentIndex, next, prev, reset, close }\">\r\n        <div class=\"custom-search-box\">\r\n          <SearchOutlined class=\"custom-search-box__icon\" />\r\n          <input\r\n              ref=\"searchInputRef\"\r\n              v-model=\"keyword.value\"\r\n              class=\"custom-search-box__input\"\r\n              placeholder=\"搜索节点名称或ID...\"\r\n              @keyup.enter=\"next\"\r\n              @keyup.esc=\"close\"\r\n              @keydown.shift.enter.prevent=\"prev\"\r\n          />\r\n          <span class=\"custom-search-box__count\">\r\n          {{ total.value > 0 ? `${currentIndex.value + 1} / ${total.value}` : '0 / 0' }}\r\n        </span>\r\n          <button class=\"custom-search-box__btn\" :disabled=\"total === 0\" @click=\"prev\" title=\"上一个 (Shift+Enter)\">↑</button>\r\n          <button class=\"custom-search-box__btn\" :disabled=\"total === 0\" @click=\"next\" title=\"下一个 (Enter)\">↓</button>\r\n          <button class=\"custom-search-box__btn\" @click=\"close\" title=\"关闭 (Esc)\">✕</button>\r\n        </div>\r\n      </template>\r\n\r\n      <!-- 【测试】画布右键菜单：纯插槽，通过 capabilities 判断权限 -->\r\n      <template #canvas-menu=\"{ capabilities, onSelect }\">\r\n        <div class=\"custom-ctx-menu\">\r\n          <div v-if=\"capabilities.canSelectAll && capabilities.canMultipleSelect\" class=\"custom-ctx-menu__item\" @click=\"onSelect('selectAll')\">\r\n            <SelectOutlined class=\"custom-ctx-menu__icon\" /><span>全选节点 (Ctrl+A)</span>\r\n          </div>\r\n          <template v-if=\"capabilities.canUndo || capabilities.canRedo\">\r\n            <div v-if=\"capabilities.canSelectAll && capabilities.canMultipleSelect\" class=\"custom-ctx-menu__divider\" />\r\n            <div v-if=\"capabilities.canUndo\" class=\"custom-ctx-menu__item\" @click=\"onSelect('undo')\">\r\n              <UndoOutlined class=\"custom-ctx-menu__icon\" /><span>撤销 (Ctrl+Z)</span>\r\n            </div>\r\n            <div v-if=\"capabilities.canRedo\" class=\"custom-ctx-menu__item\" @click=\"onSelect('redo')\">\r\n              <RedoOutlined class=\"custom-ctx-menu__icon\" /><span>重做 (Ctrl+Y)</span>\r\n            </div>\r\n          </template>\r\n          <template v-if=\"capabilities.canZoom || capabilities.canFitView\">\r\n            <div class=\"custom-ctx-menu__divider\" />\r\n            <div v-if=\"capabilities.canZoom\" class=\"custom-ctx-menu__item\" @click=\"onSelect('zoomIn')\">\r\n              <ZoomInOutlined class=\"custom-ctx-menu__icon\" /><span>放大 (Ctrl+=)</span>\r\n            </div>\r\n            <div v-if=\"capabilities.canZoom\" class=\"custom-ctx-menu__item\" @click=\"onSelect('zoomOut')\">\r\n              <ZoomOutOutlined class=\"custom-ctx-menu__icon\" /><span>缩小 (Ctrl+-)</span>\r\n            </div>\r\n            <div v-if=\"capabilities.canFitView\" class=\"custom-ctx-menu__item\" @click=\"onSelect('fitView')\">\r\n              <CompressOutlined class=\"custom-ctx-menu__icon\" /><span>适应窗口 (Ctrl+0)</span>\r\n            </div>\r\n            <div v-if=\"capabilities.canResetView\" class=\"custom-ctx-menu__item\" @click=\"onSelect('resetView')\">\r\n              <FullscreenExitOutlined class=\"custom-ctx-menu__icon\" /><span>重置视图</span>\r\n            </div>\r\n          </template>\r\n          <template v-if=\"capabilities.canImport || capabilities.canExport\">\r\n            <div class=\"custom-ctx-menu__divider\" />\r\n            <div v-if=\"capabilities.canImport\" class=\"custom-ctx-menu__item\" @click=\"onSelect('import')\">\r\n              <ImportOutlined class=\"custom-ctx-menu__icon\" /><span>导入 JSON</span>\r\n            </div>\r\n            <div v-if=\"capabilities.canExport\" class=\"custom-ctx-menu__item\" @click=\"onSelect('export')\">\r\n              <ExportOutlined class=\"custom-ctx-menu__icon\" /><span>导出 JSON</span>\r\n            </div>\r\n          </template>\r\n          <template v-if=\"capabilities.canDelete\">\r\n            <div class=\"custom-ctx-menu__divider\" />\r\n            <div class=\"custom-ctx-menu__item custom-ctx-menu__item--danger\" @click=\"onSelect('clear')\">\r\n              <ClearOutlined class=\"custom-ctx-menu__icon\" /><span>清空画布</span>\r\n            </div>\r\n          </template>\r\n        </div>\r\n      </template>\r\n\r\n      <!-- 【测试】节点右键菜单：纯插槽，通过 capabilities + isGroup/isMultiSelect 判断 -->\r\n      <template #node-menu=\"{ isGroup, isMultiSelect, capabilities, onSelect }\">\r\n        <div class=\"custom-ctx-menu\">\r\n          <div v-if=\"isMultiSelect && capabilities.canGroup\" class=\"custom-ctx-menu__item\" @click=\"onSelect('group')\">\r\n            <GroupOutlined class=\"custom-ctx-menu__icon\" /><span>成组 (Ctrl+G)</span>\r\n          </div>\r\n          <div v-if=\"isGroup && capabilities.canGroup\" class=\"custom-ctx-menu__item\" @click=\"onSelect('ungroup')\">\r\n            <UngroupOutlined class=\"custom-ctx-menu__icon\" /><span>解组 (Ctrl+Shift+G)</span>\r\n          </div>\r\n          <div v-if=\"(isMultiSelect || isGroup) && capabilities.canGroup\" class=\"custom-ctx-menu__divider\" />\r\n          <div v-if=\"capabilities.canCopy\" class=\"custom-ctx-menu__item\" @click=\"onSelect('copy')\">\r\n            <CopyOutlined class=\"custom-ctx-menu__icon\" /><span>复制节点 (Ctrl+C)</span>\r\n          </div>\r\n          <div v-if=\"capabilities.canPaste\" class=\"custom-ctx-menu__item\" @click=\"onSelect('paste')\">\r\n            <SnippetsOutlined class=\"custom-ctx-menu__icon\" /><span>粘贴节点 (Ctrl+V)</span>\r\n          </div>\r\n          <div v-if=\"capabilities.canCopy || capabilities.canPaste\" class=\"custom-ctx-menu__divider\" />\r\n          <div v-if=\"capabilities.canToFront\" class=\"custom-ctx-menu__item\" @click=\"onSelect('toFront')\">\r\n            <VerticalAlignTopOutlined class=\"custom-ctx-menu__icon\" /><span>层级前置</span>\r\n          </div>\r\n          <div v-if=\"capabilities.canToBack\" class=\"custom-ctx-menu__item\" @click=\"onSelect('toBack')\">\r\n            <VerticalAlignBottomOutlined class=\"custom-ctx-menu__icon\" /><span>层级后置</span>\r\n          </div>\r\n          <div v-if=\"capabilities.canToFront || capabilities.canToBack\" class=\"custom-ctx-menu__divider\" />\r\n          <div v-if=\"capabilities.canDelete\" class=\"custom-ctx-menu__item custom-ctx-menu__item--danger\" @click=\"onSelect('delete')\">\r\n            <DeleteOutlined class=\"custom-ctx-menu__icon\" /><span>删除节点 (Delete)</span>\r\n          </div>\r\n        </div>\r\n      </template>\r\n\r\n      <!-- 【测试】连线右键菜单：纯插槽 -->\r\n      <template #edge-menu=\"{ capabilities, onSelect }\">\r\n        <div class=\"custom-ctx-menu\">\r\n          <div v-if=\"capabilities.canDelete\" class=\"custom-ctx-menu__item custom-ctx-menu__item--danger\" @click=\"onSelect('delete')\">\r\n            <DisconnectOutlined class=\"custom-ctx-menu__icon\" /><span>删除连线 (Delete)</span>\r\n          </div>\r\n        </div>\r\n      </template>\r\n\r\n      <!-- 节点 Tooltip -->\r\n      <!--    <template #node-tooltip=\"{ node, data }\">-->\r\n      <!--      <div class=\"my-node-tooltip\" style=\"color: black\">-->\r\n      <!--        node-tooltip插槽:{{ data?.label }}&#45;&#45;{{node.shape}}-->\r\n      <!--      </div>-->\r\n      <!--    </template>-->\r\n\r\n      <!-- 连线 Tooltip -->\r\n      <!--    <template #edge-tooltip=\"{ edge, data }\">-->\r\n      <!--      <div class=\"my-edge-tooltip\">-->\r\n      <!--        edge-tooltip插槽:{{ data?.label }}-->\r\n      <!--      </div>-->\r\n      <!--    </template>-->\r\n\r\n      <!-- 【测试】edge-label 插槽：自定义连线标签 -->\r\n      <!--    <template #edge-label=\"{ edge, data }\">-->\r\n      <!--      <div class=\"custom-edge-label\" :class=\"{ 'custom-edge-label-selected': (data.state == 'hover' || data.state == 'selected') }\">-->\r\n      <!--        <TagOutlined class=\"custom-edge-label__icon\" />-->\r\n      <!--        <span class=\"custom-edge-label__text\">{{data.state}}-{{ (data as any)?.label }}</span>-->\r\n      <!--      </div>-->\r\n      <!--    </template>-->\r\n\r\n      <!--\r\n        ════════════════════════════════════════════════════════════════\r\n        【common-vue-node】插槽定义区域\r\n        ────────────────────────────────────────────────────────────────\r\n        约定：<template #node-<type>> 即可定义对应 node-type 的节点内容。\r\n        scope 包含：\r\n          - node      : X6 Node 实例（读写数据、监听事件）\r\n          - nodeType  : 当前 node-type 字符串\r\n        ════════════════════════════════════════════════════════════════\r\n      -->\r\n\r\n      <!-- node-type=\"custom-task\" 的节点内容 -->\r\n      <template #node-custom-task=\"{ node, graph }\">\r\n        <CommonNodeTask :node=\"node\" :graph=\"graph\" />\r\n      </template>\r\n\r\n      <!-- node-type=\"custom-notice\" 的节点内容 -->\r\n      <template #node-custom-notice=\"{ node, graph }\">\r\n        <CommonNodeNotice :node=\"node\" :graph=\"graph\" />\r\n      </template>\r\n    </FlowDesignerLayout>\r\n\r\n    <!-- 模式选择器（固定在右上角） -->\r\n    <ModeSelection\r\n        :designer=\"designer\"\r\n        @mode-change=\"handleModeChangeFromSelector\"\r\n    />\r\n\r\n\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref, reactive, computed } from 'vue'\r\nimport { message } from 'ant-design-vue'\r\nimport {\r\n  SelectOutlined, SearchOutlined, UndoOutlined, RedoOutlined, ZoomInOutlined, ZoomOutOutlined,\r\n  CompressOutlined, FullscreenExitOutlined, ImportOutlined, ExportOutlined, ClearOutlined,\r\n  GroupOutlined, UngroupOutlined, CopyOutlined, SnippetsOutlined,\r\n  VerticalAlignTopOutlined, VerticalAlignBottomOutlined, DeleteOutlined,\r\n  DisconnectOutlined,\r\n  TagOutlined,\r\n} from '@ant-design/icons-vue'\r\nimport { FlowDesigner } from '../components/FlowDesigner/core'\r\nimport FlowDesignerLayout from '../components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport Toolbar from './Toolbar.vue'\r\nimport NodePalette from './NodePalette.vue'\r\nimport PropertiesPanel from './PropertiesPanel.vue'\r\nimport ModeSelection from './ModeSelection.vue'\r\nimport type { FlowData, DesignerMode } from './types/flow.types'\r\nimport type {\r\n  BeforeNodeAddEvent,\r\n  AfterNodeAddEvent,\r\n  BeforeNodeRemoveEvent,\r\n  BeforeEdgeAddEvent,\r\n  AfterEdgeAddEvent,\r\n  BeforeEdgeRemoveEvent,\r\n  AfterEdgeRemoveEvent,\r\n} from '../components/FlowDesigner/types/events'\r\nimport node30 from '/testfile/node-30.json'\r\n\r\n// ─── common-vue-node 子节点组件\r\nimport CommonNodeTask   from './nodes/CommonNodeTask.vue'\r\nimport CommonNodeNotice from './nodes/CommonNodeNotice.vue'\r\nimport {\r\n  BeforeEdgeHoverEvent,\r\n  BeforeEdgeSelectEvent,\r\n  BeforeNodeSelectEvent\r\n} from \"../components/FlowDesigner/types/events\";\r\n\r\nconst layoutRef = ref<InstanceType<typeof FlowDesignerLayout> | null>(null)\r\n// 测试用：搜索框插槽内的 input 引用（用于自动聚焦）\r\nconst searchInputRef = ref<HTMLInputElement | null>(null);\r\n\r\n// ─── Designer 实例（从 layoutRef 中提取，传递给 ModeSelection）──────────────\r\nconst designer = computed(() => layoutRef.value?.designer || null)\r\n\r\n// ─── 当前模式状态 ─────────────────────────────────────────────────────────────\r\nconst currentMode = ref<DesignerMode>('design')\r\n\r\n// ─── 权限配置（简化版：只配置需要覆盖默认值的权限）────────────────────────────\r\n/**\r\n * 用户权限配置\r\n *\r\n * 说明：\r\n * 1. 只需配置需要覆盖默认值的权限项\r\n * 2. 未配置的权限项会自动使用 defaultPermissionConfig.ts 中的默认值\r\n * 3. 扩展模式会自动继承 design 模式的配置\r\n * 4. Designer 类内部会自动合并默认配置\r\n *\r\n * 默认值规则：\r\n * - design 模式：所有权限默认开启（true）\r\n * - readonly 模式：禁用编辑权限，保留查看权限\r\n * - preview 模式：最小化界面，只保留基本查看\r\n */\r\nconst permissionConfig = reactive({\r\n  // ─── 设计模式 ───\r\n  // 保持默认配置即可，如需修改可以覆盖\r\n  design: {\r\n    // UI 显示\r\n    showToolbar: true,\r\n    showNodePalette: true,\r\n    showPropertiesPanel: true,\r\n    showContextMenu: true,\r\n    showMinimap: true,\r\n    showSearch: true,\r\n\r\n    // 编辑能力\r\n    canDrag: true,\r\n    canConnect: true,\r\n    canDelete: true,\r\n    canCopy: true,\r\n    canPaste: true,\r\n    canGroup: true,\r\n    canToFront: true,\r\n    canToBack: true,\r\n    canAddNode: true,\r\n    canTransform: false,\r\n\r\n    // 选择能力\r\n    canMultipleSelect: true,\r\n    canSelectAll: true,\r\n\r\n    // 对齐能力\r\n    canAlign: true,\r\n    canAlignLeft: true,\r\n    canAlignRight: true,\r\n    canAlignTop: true,\r\n    canAlignBottom: true,\r\n\r\n    // 操作能力\r\n    canImport: true,\r\n    canExport: true,\r\n    canUndo: true,\r\n    canRedo: true,\r\n\r\n    // 视图能力\r\n    canZoom: true,\r\n    canPan: true,\r\n    canFitView: true,\r\n    canResetView: true,\r\n\r\n    // 交互反馈能力\r\n    canHoverNode: true,\r\n    canHoverEdge: true,\r\n    canSelectNode: true,\r\n    canSelectEdge: true,\r\n    canSelectCanvas: true,\r\n    canNodeTooltip: true,\r\n    canEdgeTooltip: true,\r\n\r\n    //自定义扩展权限\r\n    aaa: true,\r\n    bbb: true\r\n  },\r\n\r\n  // ─── 只读模式 ───\r\n  // 只需配置与默认值不同的权限\r\n  readonly: {\r\n    // UI 显示\r\n    showToolbar: true,\r\n    showNodePalette: true,\r\n    showPropertiesPanel: true,\r\n    showContextMenu: true,\r\n    showMinimap: true,\r\n\r\n    // 编辑能力\r\n    canDrag: false,\r\n    canConnect: false,\r\n    canDelete: false,\r\n    canCopy: false,\r\n    canPaste: false,\r\n    canGroup: false,\r\n    canToFront: false,\r\n    canToBack: false,\r\n    canAddNode: false,\r\n\r\n    // 选择能力\r\n    canMultipleSelect: false,\r\n    canSelectAll: false,\r\n\r\n    // 对齐能力\r\n    canAlign: false,\r\n    canAlignLeft: false,\r\n    canAlignRight: false,\r\n    canAlignTop: false,\r\n    canAlignBottom: false,\r\n\r\n    // 操作能力\r\n    canImport: false,\r\n    canExport: false,\r\n    canUndo: false,\r\n    canRedo: false,\r\n\r\n    // 视图能力\r\n    canZoom: true,\r\n    canPan: true,\r\n    canFitView: true,\r\n    canResetView: true,\r\n\r\n    // 交互反馈能力\r\n    canHoverNode: false,\r\n    canHoverEdge: false,\r\n    canSelectNode: false,\r\n    canSelectEdge: false,\r\n    canNodeTooltip: false,\r\n    canEdgeTooltip: false,\r\n  },\r\n\r\n  // ─── 预览模式 ───\r\n  // 默认已经最小化界面，如需调整可以覆盖\r\n  preview: {\r\n    // UI 显示\r\n    showToolbar: false,\r\n    showNodePalette: false,\r\n    showPropertiesPanel: false,\r\n    showContextMenu: false,\r\n    showMinimap: true,\r\n\r\n    // 编辑能力\r\n    canDrag: false,\r\n    canConnect: false,\r\n    canDelete: false,\r\n    canCopy: false,\r\n    canPaste: false,\r\n    canGroup: false,\r\n    canToFront: false,\r\n    canToBack: false,\r\n    canAddNode: false,\r\n\r\n    // 选择能力\r\n    canMultipleSelect: false,\r\n    canSelectAll: false,\r\n\r\n    // 对齐能力\r\n    canAlign: false,\r\n    canAlignLeft: false,\r\n    canAlignRight: false,\r\n    canAlignTop: false,\r\n    canAlignBottom: false,\r\n\r\n    // 操作能力\r\n    canImport: false,\r\n    canExport: false,\r\n    canUndo: false,\r\n    canRedo: false,\r\n\r\n    // 视图能力\r\n    canZoom: true,\r\n    canPan: true,\r\n    canFitView: true,\r\n    canResetView: true,\r\n\r\n    // 交互反馈能力\r\n    canHoverNode: false,\r\n    canHoverEdge: false,\r\n    canSelectNode: false,\r\n    canSelectEdge: false,\r\n    canNodeTooltip: false,\r\n    canEdgeTooltip: false,\r\n  },\r\n\r\n  // ─── 扩展模式示例（可选）───\r\n  // 添加自定义模式，未配置的权限会自动继承 design 模式\r\n  customMode: {\r\n    showToolbar: false,\r\n    showNodePalette: false,\r\n    showPropertiesPanel: false,\r\n    showContextMenu: false,\r\n    showMinimap: false,\r\n\r\n    aaa: false,\r\n    bbb: false\r\n  }\r\n})\r\n\r\n// 测试用：10秒后动态禁用 Node Tooltip\r\n// 注意：不需要手动调用 updatePermissions(),FlowDesignerLayout 内部会自动监听 permissionConfig 的变化\r\n// setTimeout(()=>{\r\n//   console.log('[FlowDesignerTest] 10秒后禁用 Node Tooltip')\r\n//   permissionConfig.design.canNodeTooltip = false\r\n//   console.log('[FlowDesignerTest] permissionConfig.design.canNodeTooltip =', permissionConfig.design.canNodeTooltip)\r\n// },10*1000)\r\n\r\n// 测试用：10秒后动态隐藏 Minimap\r\n// 注意：不需要手动调用 updatePermissions()，FlowDesignerLayout 内部会自动监听 permissionConfig 的变化\r\n// setTimeout(() => {\r\n//   console.log('[FlowDesignerTest] 10秒后隐藏 Minimap')\r\n//   permissionConfig.design.showMinimap = false\r\n//   console.log('[FlowDesignerTest] permissionConfig.design.showMinimap =', permissionConfig.design.showMinimap)\r\n// }, 10 * 1000)\r\n\r\n\r\n// ─── ready 回调：拿到 designer 实例后加载本地数据 ─────────────────────────────\r\nfunction handleReady(designer: FlowDesigner) {\r\n  // ─── 示例1：重写边的 hover 状态颜色为紫色 ─────────────────────────────────\r\n  // 使用 registerEdgeStateHandler  registerNodeStateHandler，方法可以自定义或重写边/节点的状态样式\r\n  // designer.registerEdgeStateHandler('hover', {\r\n  //   apply: (edge, ctx) => {\r\n  //     // 自定义 hover 状态：紫色高亮\r\n  //     edge.attr('line/stroke', '#9c27b0')  // 紫色\r\n  //     edge.attr('line/strokeWidth', 3)      // 更粗的线条\r\n  //   }\r\n  // }, true)  // override=true 表示覆盖内置的 hover 状态处理器\r\n  //\r\n  // console.log('[Ready] 已注册自定义边 hover 状态处理器（紫色）')\r\n\r\n  // ─── 示例2：注册新的边自定义状态（如 warning、error 等）────────────────\r\n  // designer.registerEdgeStateHandler('warning', {\r\n  //   apply: (edge, ctx) => {\r\n  //     edge.attr('line/stroke', '#ff9800')  // 橙色\r\n  //     edge.attr('line/strokeWidth', 2)\r\n  //     edge.attr('line/strokeDasharray', '5 5')  // 虚线\r\n  //   }\r\n  // })\r\n\r\n  // ─── 加载测试数据 ──────────────────────────────────────────────────────\r\n  if (node30) {\r\n    try {\r\n      designer.load(node30)\r\n      message.success('加载成功！')\r\n    } catch {\r\n      message.error('加载失败')\r\n    }\r\n  }\r\n}\r\n\r\n// ─── save 事件：持久化到 localStorage ────────────────────────────────────────\r\nfunction handleSave(data: FlowData) {\r\n  message.success('保存成功！')\r\n  localStorage.setItem('flow-designer-test', JSON.stringify(data))\r\n}\r\n\r\n// ─── error 事件 ───────────────────────────────────────────────────────────────\r\nfunction handleError(error: Error) {\r\n  message.error(`错误: ${error.message}`)\r\n}\r\n\r\n// ─── mode-change 事件 ─────────────────────────────────────────────────────────\r\nfunction handleModeChange(mode: DesignerMode) {\r\n  message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)\r\n  currentMode.value = mode\r\n}\r\n\r\n// ─── 从 ModeSelection 组件触发的模式切换 ─────────────────────────────────────\r\nfunction handleModeChangeFromSelector(mode: DesignerMode) {\r\n  // 🎯 调用 designer.setMode() 更新 designer 内部状态\r\n  if (designer.value) {\r\n    console.log('[FlowDesignerTest] 调用 designer.setMode()', mode)\r\n    designer.value.setMode(mode)\r\n  } else {\r\n    console.warn('[FlowDesignerTest] designer 实例不存在，无法切换模式')\r\n  }\r\n\r\n  // 更新本地状态（保持同步）\r\n  currentMode.value = mode\r\n\r\n  //message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)\r\n}\r\n\r\n// ─── 节点添加前拦截器 ──────────────────────────────────────────────────────────\r\n/**\r\n * 节点添加前拦截示例：\r\n * 1. 验证节点类型是否允许添加\r\n * 2. 检查节点数量限制\r\n * 3. 可修改节点属性（如位置、样式）\r\n * 4. 调用 preventDefault() 阻止添加\r\n */\r\nfunction handleBeforeNodeAdd(event: BeforeNodeAddEvent): boolean {\r\n  const { node, source } = event\r\n  const nodeData = node.getData()\r\n\r\n  console.log('[Before Node Add]', {\r\n    nodeId: node.id,\r\n    nodeType: nodeData?.type,\r\n    source,\r\n    position: node.getPosition(),\r\n  })\r\n  // 示例1：限制 start-node 类型节点只能添加一个\r\n  if (node.shape === 'start-node') {\r\n    const designer = layoutRef.value?.designer\r\n    if (designer) {\r\n      const graph = designer.getGraph()\r\n      const existingStartNodes = graph.getNodes().filter(n => {\r\n        return n?.shape === 'start-node'\r\n      })\r\n\r\n      if (existingStartNodes.length > 0) {\r\n        message.warning('开始节点只能添加一个！')\r\n        return false // 返回 false 阻止添加\r\n      }\r\n    }\r\n  }\r\n\r\n  // 示例2：自动吸附到网格（20px）\r\n  const pos = node.getPosition()\r\n  const snappedX = Math.round(pos.x / 20) * 20\r\n  const snappedY = Math.round(pos.y / 20) * 20\r\n  if (pos.x !== snappedX || pos.y !== snappedY) {\r\n    // ✅ 使用 silent: true 避免触发 change:position 事件\r\n    // beforeNodeAdd 是预处理阶段,修改应该是静默的,不应产生独立的历史记录\r\n    node.setPosition({ x: snappedX, y: snappedY }, { silent: true })\r\n    console.log('[Before Node Add] 位置已吸附到网格:', { x: snappedX, y: snappedY })\r\n  }\r\n\r\n  // 示例3：根据来源添加自定义标记\r\n  if (source === 'paste') {\r\n    const currentData = node.getData() || {}\r\n    // ✅ 使用 silent: true 避免触发 change:data 事件\r\n    node.setData({\r\n      ...currentData,\r\n      _pastedAt: Date.now(),\r\n    }, { silent: true })\r\n    console.log('[Before Node Add] 已标记粘贴时间')\r\n  }\r\n\r\n  return true // 返回 true 允许添加\r\n}\r\n\r\n// ─── 节点添加后回调 ────────────────────────────────────────────────────────────\r\n/**\r\n * 节点添加后通知示例：\r\n * 1. 记录操作日志\r\n * 2. 更新统计数据\r\n * 3. 同步到外部系统\r\n */\r\nfunction handleAfterNodeAdd(event: AfterNodeAddEvent) {\r\n  const { nodeId, source, success, timestamp } = event\r\n\r\n  if (success) {\r\n    console.log('[After Node Add] 节点添加成功', {\r\n      nodeId,\r\n      source,\r\n      timestamp: new Date(timestamp).toLocaleTimeString(),\r\n    })\r\n\r\n    // ── common-vue-node：从 data.nodeType 读取类型并写入 node prop ──────────\r\n    // NodePalette 拖入时在 data 里携带了 nodeType 字段，这里转存到 X6 prop\r\n    const graph = layoutRef.value?.designer?.getGraph()\r\n    const node = graph?.getCellById(nodeId)\r\n    if (node?.isNode() && node.shape === 'common-vue-node') {\r\n      const nodeType = node.getData()?.nodeType\r\n      if (nodeType) {\r\n        node.setProp('node-type', nodeType)\r\n      }\r\n    }\r\n\r\n    // 示例：显示通知（仅非撤销/重做操作）\r\n    if (source !== 'undo' && source !== 'redo') {\r\n      message.success(`节点已添加（来源: ${source}）`, 2)\r\n    }\r\n  } else {\r\n    console.error('[After Node Add] 节点添加失败', event.error)\r\n  }\r\n}\r\n\r\n/**\r\n * 节点删除前拦截示例：\r\n * 1. 禁止删除特定类型的节点（如结束节点）\r\n * 2. 删除前确认\r\n * 3. 根据来源显示不同提示\r\n */\r\nfunction handleBeforeNodeRemove(event: BeforeNodeRemoveEvent): boolean {\r\n  const { node, source } = event\r\n\r\n  console.log('[Before Node Remove]', {\r\n    nodeId: node.id,\r\n    nodeShape: node.shape,\r\n    source,\r\n  })\r\n\r\n  // 示例1：禁止删除结束节点\r\n  if (node.shape === 'end-node') {\r\n    message.warning('结束节点不能删除！')\r\n    return false // 返回 false 阻止删除\r\n  }\r\n\r\n  // 示例2：开始节点删除前确认\r\n  if (node.shape === 'start-node' && source === 'keyboard') {\r\n    // 注意：这里只是演示，实际生产环境中不建议在拦截器中使用同步 confirm\r\n    // 应该使用 Modal.confirm 等异步确认方式\r\n    message.info(`正在删除开始节点（来源: ${source}）`)\r\n  }\r\n\r\n  // 示例3：批量删除时的提示\r\n  if (source === 'clear') {\r\n    console.log('[Before Node Remove] 画布清空操作，节点将被删除:', node.id)\r\n  }\r\n\r\n  return true // 返回 true 允许删除\r\n}\r\n\r\n// ─── 连线创建前拦截器 ──────────────────────────────────────────────────────────\r\n/**\r\n * 连线创建前拦截示例（在 validateConnection 阶段触发）：\r\n * sourceCell/targetCell 均已知，可做完整的双端规则校验\r\n * 调用 preventDefault() 阻止连线创建\r\n */\r\nfunction handleBeforeEdgeAdd(event: BeforeEdgeAddEvent): boolean {\r\n  const { sourceCell, targetCell, sourceMagnet, targetMagnet } = event\r\n\r\n  console.log('[Before Edge Add] validateConnection 阶段拦截', {\r\n    sourceCellId: sourceCell.id,\r\n    sourceCellShape: (sourceCell as any).shape,\r\n    targetCellId: targetCell.id,\r\n    targetCellShape: (targetCell as any).shape,\r\n  });\r\n\r\n  // 基础规则验证\r\n  // const srcGroup = sourceMagnet?.getAttribute('port-group') ?? ''\r\n  // const tgtGroup = targetMagnet?.getAttribute('port-group') ?? ''\r\n  // const validSrc = ['out', 'right', 'bottom', 'left'].includes(srcGroup)\r\n  // if (!validSrc || !sourceMagnet) return false;\r\n  // if (tgtGroup !== 'in' || !targetMagnet) return false;\r\n  // if ((targetCell as any)?.shape === 'start-node') return false;\r\n  // if ((sourceCell as any)?.shape === 'end-node') return false;\r\n  // if (sourceCell === targetCell) return false;\r\n\r\n  const designer = layoutRef.value?.designer\r\n  if (!designer) return true\r\n\r\n  const graph = designer.getGraph()\r\n\r\n  // 示例1：禁止特定节点类型互连（条件节点 → 开始节点）\r\n  if ((sourceCell as any).shape === 'condition-node' && (targetCell as any).shape === 'start-node') {\r\n    message.warning('条件节点不能连接到开始节点！')\r\n    return false // 返回 false 阻止连接\r\n  }\r\n\r\n  // 示例2：限制单个节点最多3条出度\r\n  const sourceEdges = graph.getConnectedEdges(sourceCell, { outgoing: true })\r\n  if (sourceEdges.length >= 3) {\r\n    message.warning('单个节点最多只能连接3条出线！')\r\n    return false\r\n  }\r\n\r\n  // 示例3：限制单个节点最多2条入度\r\n  const targetEdges = graph.getConnectedEdges(targetCell, { incoming: true })\r\n  if (targetEdges.length >= 2) {\r\n    message.warning('单个节点最多只能接收2条入线！')\r\n    return false\r\n  }\r\n\r\n  // 示例4：检测双向连线（A→B 后禁止 B→A）\r\n  const hasReverse = graph.getEdges().some(e => {\r\n    return e.getSourceCell()?.id === targetCell.id && e.getTargetCell()?.id === sourceCell.id\r\n  })\r\n  if (hasReverse) {\r\n    message.warning('不允许创建双向连线！')\r\n    return false\r\n  }\r\n\r\n  console.log('[Before Edge Add] 验证通过，允许创建连线')\r\n  return true // 返回 true 允许连接\r\n}\r\n\r\n// ─── 连线添加后回调 ────────────────────────────────────────────────────────────\r\n/**\r\n * 连线添加后通知示例：\r\n * 1. 记录连线日志\r\n * 2. 更新流程统计\r\n * 3. 同步到外部系统\r\n */\r\nfunction handleAfterEdgeAdd(event: AfterEdgeAddEvent) {\r\n  const { edgeId, sourceNodeId, targetNodeId, sourceAction, success, timestamp } = event\r\n\r\n  if (success) {\r\n    console.log('[After Edge Add] 连线创建成功', {\r\n      edgeId,\r\n      sourceNodeId,\r\n      targetNodeId,\r\n      sourceAction,\r\n      timestamp: new Date(timestamp).toLocaleTimeString(),\r\n    })\r\n\r\n    // 示例：显示通知（仅非撤销/重做操作）\r\n    if (sourceAction !== 'undo' && sourceAction !== 'redo') {\r\n      message.success(`连线已创建（来源: ${sourceAction}）`, 2)\r\n    }\r\n  } else {\r\n    console.error('[After Edge Add] 连线创建失败', event.error)\r\n    message.error('连线创建失败！')\r\n  }\r\n}\r\n\r\n// ─── 连线删除前拦截器 ──────────────────────────────────────────────────────────\r\n/**\r\n * 连线删除前拦截示例：\r\n * 1. 禁止删除特定连线（如关键路径上的连线）\r\n * 2. 根据来源显示不同提示\r\n * 3. 调用 preventDefault() 阻止删除\r\n */\r\nfunction handleBeforeEdgeRemove(event: BeforeEdgeRemoveEvent): boolean {\r\n  const { edge, edgeId, sourceNodeId, targetNodeId, source } = event\r\n\r\n  console.log('[Before Edge Remove]', {\r\n    edgeId,\r\n    sourceNodeId,\r\n    targetNodeId,\r\n    source,\r\n  })\r\n\r\n  // 示例1：禁止删除带有 locked 标记的连线\r\n  const edgeData = edge.getData()\r\n  if (edgeData?.locked) {\r\n    message.warning('该连线已被锁定，不允许删除！')\r\n    return false // 返回 false 阻止删除\r\n  }\r\n\r\n  // 示例2：清空画布时记录日志，不阻止\r\n  if (source === 'clear') {\r\n    console.log('[Before Edge Remove] 画布清空操作，连线将被删除:', edgeId)\r\n  }\r\n\r\n  return true // 返回 true 允许删除\r\n}\r\n\r\n// ─── 连线删除后回调 ────────────────────────────────────────────────────────────\r\n/**\r\n * 连线删除后通知示例：\r\n * 1. 记录删除日志\r\n * 2. 同步到外部系统\r\n */\r\nfunction handleAfterEdgeRemove(event: AfterEdgeRemoveEvent) {\r\n  const { edgeId, sourceNodeId, targetNodeId, source } = event\r\n\r\n  console.log('[After Edge Remove] 连线已删除', {\r\n    edgeId,\r\n    sourceNodeId,\r\n    targetNodeId,\r\n    source,\r\n  })\r\n\r\n  // 示例：显示通知（仅非撤销/重做操作）\r\n  if (source !== 'undo' && source !== 'redo') {\r\n    message.info(`连线已删除（来源: ${source}）`, 2)\r\n  }\r\n}\r\n\r\n// ─── 数据加载完成事件 ─────────────────────────────────────────────────────────\r\n/**\r\n * afterDataLoaded：数据加载完成后，居中显示顶层起始节点（入度为 0 的节点）\r\n */\r\nfunction handleAfterDataLoaded(data: FlowData) {\r\n  console.log('[After Data Loaded] 画布数据加载完成，cells 数:', data.cells?.length ?? 0)\r\n  const designer = layoutRef.value?.designer\r\n  if (!designer) return\r\n  // 获取顶层起始节点（入度为 0）\r\n  const rootNodes = designer.getRootNodes()\r\n  if (rootNodes.length > 0) {\r\n    //layoutRef.value?.centerNode(rootNodes[0].id)\r\n    //console.log('[After Data Loaded] 已居中显示顶层节点:', rootNodes[0].id)\r\n  } else {\r\n    console.log('[After Data Loaded] 未找到顶层节点')\r\n  }\r\n}\r\n\r\n\r\n/**\r\n * :before-node-select 钩子函数\r\n * 返回 false 可阻止节点选择\r\n */\r\nfunction handleBeforeNodeSelect(event: BeforeNodeSelectEvent): boolean {\r\n  return true\r\n  if (true) {\r\n    console.log(`❌ 节点选择被阻止`)\r\n    return false // 返回 false 阻止选择\r\n  }\r\n  console.log(`✅ 允许节点选择`)\r\n  return true // 返回 true 允许选择\r\n}\r\n\r\n/**\r\n * :before-edge-select 钩子函数\r\n * 返回 false 可阻止连线选择\r\n */\r\nfunction handleBeforeEdgeSelect(event: BeforeEdgeSelectEvent): boolean {\r\n  return true\r\n  if (true) {\r\n    return false // 返回 false 阻止选择\r\n  }\r\n  return true // 返回 true 允许选择\r\n}\r\n\r\n\r\n/**\r\n * :before-edge-hover 钩子函数\r\n * 返回 false 可阻止连线悬停效果\r\n */\r\nfunction handleBeforeEdgeHover(event: BeforeEdgeHoverEvent): boolean {\r\n  return true\r\n  if (false) {\r\n    return false // 返回 false 阻止悬停效果\r\n  }\r\n  return true // 返回 true 允许悬停\r\n}\r\n\r\ndefineExpose({ layoutRef })\r\n</script>\r\n\r\n<style scoped>\r\n.flow-designer-test {\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n\r\n/* ── 测试用自定义右键菜单样式 ────────────────────────────────────────────── */\r\n.custom-ctx-menu {\r\n  background: #fff;\r\n