 {\r\n  border-color: #1890ff;\r\n  color: #1890ff;\r\n}\r\n\r\n.custom-search-box__btn:disabled {\r\n  color: #bfbfbf;\r\n  cursor: not-allowed;\r\n}\r\n.my-node-tooltip {\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 4px;\r\n  padding: 8px;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);\r\n}\r\n.my-edge-tooltip {\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 4px;\r\n  padding: 8px;\r\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);\r\n}\r\n.abc {\r\n  fill: red\r\n}\r\n\r\n/* 【测试】自定义连线标签 */\r\n.custom-edge-label {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  gap: 4px;\r\n  padding: 2px 8px;\r\n  background: #fff;\r\n  border: 1px solid #cce3f9;\r\n  border-radius: 3px;\r\n  font-size: 12px;\r\n  color: #999999;\r\n  white-space: nowrap;\r\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\r\n  pointer-events: none;\r\n  font-weight: 500;\r\n  filter: drop-shadow(0 1px 2px rgba(0, 0, 0, 0.1));\r\n}\r\n.custom-edge-label-selected {\r\n  color: #1677ff;\r\n  border: 1px solid #1677ff;\r\n}\r\n\r\n.custom-edge-label__icon {\r\n  font-size: 11px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-edge-label__text {\r\n  max-width: 80px;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n</style>\r\n"