export default "﻿<template>\r\n  <div class=\"demo-mode-change\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-mode-change__log\">\r\n      <div class=\"demo-mode-change__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-mode-change__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-mode-change__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-mode-change__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-mode-change__canvas\">\r\n      <!-- 模式切换按钮 -->\r\n      <div class=\"demo-mode-change__controls\">\r\n        <button\r\n          v-for=\"mode in modes\"\r\n          :key=\"mode.value\"\r\n          class=\"demo-mode-change__btn\"\r\n          :class=\"{ 'demo-mode-change__btn--active': currentMode === mode.value }\"\r\n          @click=\"changeMode(mode.value)\"\r\n        >\r\n          {{ mode.label }}\r\n        </button>\r\n      </div>\r\n\r\n      <FlowDesignerLayout\r\n        :mode=\"currentMode\"\r\n        @mode-change=\"handleModeChange\"\r\n        @ready=\"handleReady\"\r\n      />\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Graph } from '@antv/x6'\r\n\r\nconst logs = ref<string[]>([])\r\nconst currentMode = ref<'design' | 'readonly' | 'preview'>('design')\r\nconst designerRef = ref<FlowDesigner>()\r\n\r\nconst modes = [\r\n  { value: 'design', label: '✏️ 设计模式' },\r\n  { value: 'readonly', label: '👁 只读模式' },\r\n  { value: 'preview', label: '📺 预览模式' },\r\n]\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\nfunction handleReady(designer, graph) {\r\n  designerRef.value = designer\r\n  addLog('✅ 画布初始化完成')\r\n  addLog(`🔧 当前模式: ${designer.getMode()}`)\r\n\r\n  // 添加初始节点\r\n  graph.addNode({\r\n    shape: 'rect',\r\n    x: 150,\r\n    y: 100,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点1',\r\n    attrs: {\r\n      body: { fill: '#5F95FF', stroke: '#2563EB' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n\r\n  graph.centerContent()\r\n}\r\n\r\n/**\r\n * @mode-change 事件处理函数\r\n * 参数：mode - 新的模式名称\r\n */\r\nfunction handleModeChange(mode: string) {\r\n  addLog(`🔄 @mode-change 事件触发`)\r\n  addLog(`📌 新模式: ${mode}`)\r\n\r\n  if (designerRef.value) {\r\n    const caps = designerRef.value.getCapabilities()\r\n    addLog(`🔐 canDrag: ${caps.canDrag}`)\r\n    addLog(`🔐 canDelete: ${caps.canDelete}`)\r\n    addLog(`🔐 canConnect: ${caps.canConnect}`)\r\n  }\r\n}\r\n\r\nfunction changeMode(mode: 'design' | 'readonly' | 'preview') {\r\n  addLog(`👆 切换到 ${mode} 模式`)\r\n  currentMode.value = mode\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-mode-change {\r\n  display: flex;\r\n  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */\r\n  min-height: 400px; /* 添加：最小高度，非全屏时保持合理尺寸 */\r\n  gap: 16px;\r\n}\r\n\r\n.demo-mode-change__log {\r\n  width: 300px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-mode-change__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-mode-change__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-mode-change__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-mode-change__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-mode-change__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-mode-change__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-mode-change__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-mode-change__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-mode-change__controls {\r\n  display: flex;\r\n  gap: 8px;\r\n  padding: 12px;\r\n  background: #fff;\r\n  border-bottom: 1px solid #e8e8e8;\r\n}\r\n\r\n.demo-mode-change__btn {\r\n  padding: 6px 16px;\r\n  font-size: 13px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.demo-mode-change__btn:hover {\r\n  color: #1677ff;\r\n  border-color: #1677ff;\r\n}\r\n\r\n.demo-mode-change__btn--active {\r\n  color: #fff;\r\n  background: #1677ff;\r\n  border-color: #1677ff;\r\n}\r\n</style>\r\n"