<template>
  <div class="demo-slot-toolbar">
    <!-- 事件日志面板 -->
    <div class="demo-slot-toolbar__log">
      <div class="demo-slot-toolbar__log-header">
        <h4>事件日志</h4>
        <button class="demo-slot-toolbar__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-slot-toolbar__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-slot-toolbar__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-slot-toolbar__canvas">
      <FlowDesignerLayout
        mode="design"
        @ready="handleReady"
      >
        <!-- 顶部工具栏 -->
        <template #toolbar="scope">
          <Toolbar
              :zoom-percent="scope.zoomPercent"
              :has-selection="scope.hasSelection"
              :can-paste="scope.canPaste"
              :can-group="scope.canGroup"
              :can-ungroup="scope.canUngroup"
              :can-undo="scope.canUndo"
              :can-redo="scope.canRedo"
              :designer-mode="scope.currentMode"
              @undo="scope.onUndo"
              @redo="scope.onRedo"
              @zoom-in="scope.onZoomIn"
              @zoom-out="scope.onZoomOut"
              @zoom-to="scope.onZoomTo"
              @fit-view="scope.onFitView"
              @reset-view="scope.onResetView"
              @copy="scope.onCopy"
              @paste="scope.onPaste"
              @to-front="scope.onToFront"
              @to-back="scope.onToBack"
              @align-left="scope.onAlignLeft"
              @align-right="scope.onAlignRight"
              @align-top="scope.onAlignTop"
              @align-bottom="scope.onAlignBottom"
              @group="scope.onGroup"
              @ungroup="scope.onUngroup"
              @export="scope.onExport"
              @import="scope.onImport"
              @open-settings="scope.onOpenSettings"
              @mode-change="scope.onModeChange"
          />
        </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner } from '@quick-code/x6-flow-designer'
import type { Graph } from '@antv/x6'
import Toolbar from './components/Toolbar.vue'

const logs = ref<string[]>([])

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}

function getModeLabel(mode: string): string {
  const labels: Record<string, string> = {
    design: '✏️ 设计',
    readonly: '👁 只读',
    preview: '📺 预览',
  }
  return labels[mode] || mode
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  addLog('✅ 画布初始化完成')
  addLog('🎨 自定义工具栏已渲染')

  // 添加初始节点
  const node1 = graph.createNode({
    shape: 'rect',
    x: 30,
    y: 30,
    width: 100,
    height: 60,
    label: `节点1`,
    attrs: {
      body: {
        fill: '#5F95FF',
        stroke: '#2563EB',
        strokeWidth: 2,
        rx: 6,
        ry: 6,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  });
  designer.addCell(node1)
  addLog(`➕ 添加节点1`);

  const node2 = graph.createNode({
    shape: 'rect',
    x: 130,
    y: 130,
    width: 100,
    height: 60,
    label: `节点2  `,
    attrs: {
      body: {
        fill: '#fc01b4',
        stroke: '#7c0073',
        strokeWidth: 2,
        rx: 6,
        ry: 6,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  });
  designer.addCell(node2)
  addLog(`➕ 添加节点2`);



  //graph.centerContent()
}

function handleUndo(undoFn: () => void) {
  addLog('↶ 执行撤销操作')
  undoFn()
}

function handleRedo(redoFn: () => void) {
  addLog('↷ 执行重做操作')
  redoFn()
}

function handleZoomIn(zoomInFn: () => void) {
  addLog('🔍 放大画布')
  zoomInFn()
}

function handleZoomOut(zoomOutFn: () => void) {
  addLog('🔍 缩小画布')
  zoomOutFn()
}

function handleZoomToFit(zoomToFitFn: () => void) {
  addLog('⊡ 适应画布')
  zoomToFitFn()
}
</script>

<style scoped>
.demo-slot-toolbar {
  display: flex;
  height: 100%;
  min-height: 450px;
  gap: 16px;
}

.demo-slot-toolbar__log {
  width: 280px;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-slot-toolbar__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-slot-toolbar__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-slot-toolbar__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-slot-toolbar__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-slot-toolbar__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-slot-toolbar__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-slot-toolbar__log-item:last-child {
  border-bottom: none;
}

.demo-slot-toolbar__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
}

/* ==================== 自定义工具栏样式 ==================== */
.custom-toolbar {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 16px;
  background: linear-gradient(to bottom, #ffffff, #f9fafb);
  border-bottom: 1px solid #e8e8e8;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.04);
}

.custom-toolbar__section {
  display: flex;
  align-items: center;
  gap: 8px;
}

.custom-toolbar__divider {
  width: 1px;
  height: 20px;
  background: #e8e8e8;
}

.custom-toolbar__label {
  font-size: 13px;
  color: #666;
  font-weight: 500;
}

.custom-toolbar__badge {
  padding: 3px 10px;
  border-radius: 12px;
  font-size: 12px;
  font-weight: 500;
  background: #f0f0f0;
  color: #555;
}

.custom-toolbar__badge--design {
  background: #e6f7ff;
  color: #1677ff;
}

.custom-toolbar__badge--readonly {
  background: #fff7e6;
  color: #fa8c16;
}

.custom-toolbar__badge--preview {
  background: #f6ffed;
  color: #52c41a;
}

.custom-toolbar__btn {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 5px 12px;
  font-size: 13px;
  color: #555;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  font-weight: 500;
  user-select: none;
}

.custom-toolbar__btn:hover:not(:disabled) {
  color: #1677ff;
  border-color: #1677ff;
  background: #f0f7ff;
}

.custom-toolbar__btn:active:not(:disabled) {
  transform: translateY(1px);
}

.custom-toolbar__btn:disabled {
  color: #bbb;
  border-color: #e8e8e8;
  background: #f5f5f5;
  cursor: not-allowed;
  opacity: 0.6;
}

.custom-toolbar__btn--icon {
  padding: 5px 10px;
  min-width: 32px;
  justify-content: center;
}

.custom-toolbar__icon {
  font-size: 16px;
  line-height: 1;
  font-weight: bold;
}

.custom-toolbar__zoom-display {
  min-width: 50px;
  text-align: center;
  font-size: 13px;
  font-weight: 600;
  color: #1677ff;
  padding: 4px 8px;
  border-radius: 4px;
  background: #f0f7ff;
  cursor: pointer;
  user-select: none;
  transition: all 0.2s;
}

.custom-toolbar__zoom-display:hover {
  background: #e6f0ff;
}
</style>
