<template>
  <div class="demo-ready">
    <!-- 事件日志面板 -->
    <div class="demo-ready__log">
      <div class="demo-ready__log-header">
        <h4>事件日志</h4>
        <button class="demo-ready__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-ready__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-ready__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-ready__canvas">
      <FlowDesignerLayout @ready="handleReady" />
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner } from '@quick-code/x6-flow-designer'
import type { Graph } from '@antv/x6'

const logs = ref<string[]>([])

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}

/**
 * @ready 事件处理函数
 * 参数：{ designer, graph } - FlowDesigner 实例和 X6 Graph 实例
 */
function handleReady(designer:FlowDesigner, graph: Graph) {
  addLog('✅ ready 事件触发')
  addLog(`📦 designer 实例ID: ${designer.id}`)
  addLog(`📊 graph 节点数: ${graph.getNodes().length}`)
  addLog(`🔗 graph 连线数: ${graph.getEdges().length}`)

  // 演示：添加几个节点
  const node1 = graph.addNode({
    shape: 'rect',
    x: 100,
    y: 100,
    width: 100,
    height: 60,
    label: '节点1',
    attrs: {
      body: {
        fill: '#5F95FF',
        stroke: '#2563EB',
        strokeWidth: 2,
      },
      label: {
        fill: '#ffffff',
        fontSize: 14,
        fontWeight: 'bold',
      },
    },
  })

  const node2 = graph.addNode({
    shape: 'rect',
    x: 300,
    y: 100,
    width: 100,
    height: 60,
    label: '节点2',
    attrs: {
      body: {
        fill: '#10B981',
        stroke: '#059669',
        strokeWidth: 2,
      },
      label: {
        fill: '#ffffff',
        fontSize: 14,
        fontWeight: 'bold',
      },
    },
  })

  graph.addEdge({
    shape: 'flow-edge',
    source: node1,
    target: node2,
    labels: ['连接'],
  })

  addLog('✨ 已添加 2 个节点和 1 条连线')

  // 演示：调用 designer 方法
  graph.centerContent()
  addLog('🎯 已居中显示内容')

  // 额外信息：演示 designer 的其他 API
  addLog(`🔧 designer.getMode(): ${designer.getMode()}`)
  addLog(`🔐 designer.can('canDrag'): ${designer.can('canDrag')}`)
}
</script>

<style scoped>
.demo-ready {
  display: flex;
  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */
  min-height: 400px; /* 添加：最小高度，非全屏时保持合理尺寸 */
  gap: 16px;
}

.demo-ready__log {
  width: 300px;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-ready__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-ready__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-ready__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-ready__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-ready__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-ready__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-ready__log-item:last-child {
  border-bottom: none;
}

.demo-ready__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
}
</style>
