<template>
  <div class="demo-slot-searchbox">
    <!-- 事件日志面板 -->
    <div class="demo-slot-searchbox__log">
      <div class="demo-slot-searchbox__log-header">
        <h4>事件日志</h4>
        <button class="demo-slot-searchbox__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-slot-searchbox__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-slot-searchbox__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-slot-searchbox__canvas">
      <FlowDesignerLayout
        mode="design"
        @ready="handleReady"
      >
        <!-- 自定义搜索框插槽 -->
        <template #search-box="{ keyword, results, currentIndex, total, next, prev, close, selectByIndex, getNodeLabel: getLabel, setFilter }">
          <div class="compact-search-box" @click.stop>
            <!-- 过滤器选择器 -->
            <div class="compact-search-box__filter-bar">
              <span class="compact-search-box__filter-label">过滤模式:</span>
              <button
                v-for="filter in filterOptions"
                :key="filter.value"
                class="compact-search-box__filter-btn"
                :class="{ 'compact-search-box__filter-btn--active': activeFilter === filter.value }"
                @click="handleFilterChange(filter.value, setFilter)"
                :title="filter.description"
              >
                {{ filter.label }}
              </button>
            </div>

            <!-- 输入框和控制按钮 -->
            <div class="compact-search-box__input-wrapper">
              <input
                ref="searchInputRef"
                v-model="keyword.value"
                class="compact-search-box__input"
                type="text"
                placeholder="搜索节点..."
                @keydown.esc="close"
                @keydown.enter.exact="next"
                @keydown.enter.shift="prev"
              />

              <!-- 结果计数和导航按钮 -->
              <div class="compact-search-box__controls">
                <span v-if="total.value > 0" class="compact-search-box__counter">
                  {{ currentIndex.value + 1 }} / {{ total.value }}
                </span>
                <span v-else-if="keyword.value && total.value === 0" class="compact-search-box__counter">
                  0 / 0
                </span>

                <button
                  class="compact-search-box__nav-btn"
                  :disabled="total.value === 0"
                  @click="prev"
                  title="上一个 (Shift+Enter)"
                >
                  ↑
                </button>
                <button
                  class="compact-search-box__nav-btn"
                  :disabled="total.value === 0"
                  @click="next"
                  title="下一个 (Enter)"
                >
                  ↓
                </button>
                <button
                  class="compact-search-box__close-btn"
                  @click="close"
                  title="关闭 (ESC)"
                >
                  ✕
                </button>
              </div>
            </div>

            <!-- 搜索结果下拉列表 -->
            <div v-if="results.value.length > 0" class="compact-search-box__dropdown">
              <div
                v-for="(result, index) in results.value"
                :key="result.id"
                class="compact-search-box__result-item"
                :class="{ 'compact-search-box__result-item--active': index === currentIndex.value }"
                @click="selectByIndex(index); addLog(`📍 已选中: ${getLabel(result)}`)"
              >
                <div class="compact-search-box__result-icon">📍</div>
                <div class="compact-search-box__result-info">
                  <div class="compact-search-box__result-label">
                    {{ getLabel(result) }}
                  </div>
                  <div class="compact-search-box__result-meta">
                    <span class="compact-search-box__result-type">{{ getNodeShape(result) }}</span>
                    <span class="compact-search-box__result-id">{{ getNodeId(result) }}</span>
                  </div>
                </div>
                <div class="compact-search-box__result-arrow">→</div>
              </div>
            </div>

            <!-- 空状态提示 -->
            <div v-else-if="keyword.value" class="compact-search-box__empty">
              未找到匹配的节点
            </div>
          </div>
        </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, watch, nextTick } from 'vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner, FlowDesignerOptions } from '@quick-code/x6-flow-designer'
import type { Graph, Node } from '@antv/x6'

const logs = ref<string[]>([])
const searchInputRef = ref<HTMLInputElement>()
let designerInstance: FlowDesigner | null = null
let graphInstance: Graph | null = null

// 过滤器选项
const activeFilter = ref<string>('all')
const filterOptions = [
  {
    value: 'all',
    label: '全部',
    description: '搜索所有节点（默认行为）'
  },
  {
    value: 'rect',
    label: '矩形',
    description: '仅搜索 rect 类型的节点'
  },
  {
    value: 'circle',
    label: '圆形',
    description: '仅搜索 circle 类型的节点'
  },
  {
    value: 'ellipse',
    label: '椭圆',
    description: '仅搜索 ellipse 类型的节点'
  },
]

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}

/**
 * 处理过滤器切换
 * @param filterValue 过滤器类型
 * @param setFilter 来自插槽的 setFilter 方法
 */
function handleFilterChange(filterValue: string, setFilter: (fn) => void) {
  activeFilter.value = filterValue

  if (filterValue === 'all') {
    // 恢复默认过滤器
    setFilter(null)
    addLog('🔍 已切换到【全部】模式')
    addLog('   → 输入关键词即可搜索所有节点')
  } else {
    // 设置自定义过滤器：仅搜索指定 shape 类型的节点
    const customFilter = (node: Node, keyword: string) => {
      // 首先检查节点类型
      if (node.shape !== filterValue) {
        return false
      }

      // 然后检查关键词匹配
      if (!keyword) return true

      const lowerKeyword = keyword.toLowerCase()

      // 获取节点标签（与 getNodeLabel 逻辑保持一致）
      const propLabel = node.getProp('label') || node.label
      if (propLabel && String(propLabel).toLowerCase().includes(lowerKeyword)) {
        return true
      }

      const dataLabel = node.getData()?.label
      if (dataLabel && String(dataLabel).toLowerCase().includes(lowerKeyword)) {
        return true
      }

      const nodeId = node.id
      if (nodeId && nodeId.toLowerCase().includes(lowerKeyword)) {
        return true
      }

      return false
    }

    setFilter(customFilter)
    const shapeMap: Record<string, string> = {
      'rect': '矩形',
      'circle': '圆形',
      'ellipse': '椭圆'
    }
    addLog(`🔍 已切换到【${shapeMap[filterValue] || filterValue}】模式`)
    addLog(`   → 仅搜索 ${filterValue} 类型的节点`)
  }
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  designerInstance = designer
  graphInstance = graph
  addLog('✅ 画布初始化完成')

  // 添加不同类型的测试节点
  const testNodes = [
    { shape: 'rect', x: 100, y: 100, width: 100, height: 60, label: '开始节点'},
    { shape: 'rect', x: 300, y: 100, width: 100, height: 60, label: '处理数据'},
    { shape: 'circle', x: 500, y: 130, width: 80, height: 80, label: '验证结果'},
    { shape: 'ellipse', x: 100, y: 250, width: 120, height: 60, label: '发送通知'},
    { shape: 'rect', x: 300, y: 250, width: 100, height: 60, label: '结束节点'},
    { shape: 'circle', x: 500, y: 280, width: 80, height: 80, label: '备份数据'},
  ]

  testNodes.forEach(node => {
    graph.addNode(node)
  })

  addLog(`🎨 已添加 ${testNodes.length} 个测试节点`)
  addLog('   → 3个矩形(rect) + 2个圆形(circle) + 1个椭圆(ellipse)')
  addLog('💡 提示: 按 Ctrl+F 打开搜索框')
  addLog('💡 测试步骤:')
  addLog('   1. 输入"节点"关键词')
  addLog('   2. 点击不同过滤按钮观察结果变化')
  addLog('   3. "矩形"模式只显示3个rect节点')
  addLog('   4. "圆形"模式只显示2个circle节点')
}

/**
 * 获取节点类型
 */
function getNodeShape(node: any): string {
  return node.shape || 'unknown'
}

/**
 * 获取节点 ID（前 8 位）
 */
function getNodeId(node: any): string {
  const id = node.id || ''
  return `ID: ${id.substring(0, 8)}`
}

/**
 * 监听搜索框显示状态，自动聚焦输入框
 */
watch(() => searchInputRef.value, (input) => {
  if (input) {
    nextTick(() => {
      input.focus()
    })
  }
})
</script>


