<template>
  <div class="demo-data-loaded">
    <!-- 事件日志面板 -->
    <div class="demo-data-loaded__log">
      <div class="demo-data-loaded__log-header">
        <h4>事件日志</h4>
        <button class="demo-data-loaded__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-data-loaded__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-data-loaded__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-data-loaded__canvas">
      <div class="demo-data-loaded__controls">
        <button class="demo-data-loaded__btn" @click="loadData">
          📥 加载示例数据
        </button>
        <button class="demo-data-loaded__btn" @click="clearCanvas">
          🗑 清空画布
        </button>
      </div>
      <FlowDesignerLayout
        @ready="handleReady"
        :after-data-loaded="handleAfterDataLoaded"
      />
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner } from '@quick-code/x6-flow-designer'
import type { Graph } from '@antv/x6'
import type { FlowData } from '@/components/FlowDesigner/types'

const logs = ref<string[]>([])
const designerRef = ref<FlowDesigner>()

// 示例流程数据
const sampleData = {
  meta: {
    name: '示例流程',
    version: '1.0.0',
  },
  nodes: [
    {
      id: 'start',
      shape: 'rect',
      x: 100,
      y: 100,
      width: 100,
      height: 60,
      data: { label: '开始' },
      attrs: {
        body: { fill: '#10B981', stroke: '#059669' },
        label: { text: '开始', fill: '#fff' },
      },
    },
    {
      id: 'process1',
      shape: 'rect',
      x: 250,
      y: 100,
      width: 100,
      height: 60,
      data: { label: '处理1' },
      attrs: {
        body: { fill: '#5F95FF', stroke: '#2563EB' },
        label: { text: '处理1', fill: '#fff' },
      },
    },
    {
      id: 'process2',
      shape: 'rect',
      x: 400,
      y: 100,
      width: 100,
      height: 60,
      data: { label: '处理2' },
      attrs: {
        body: { fill: '#F59E0B', stroke: '#D97706' },
        label: { text: '处理2', fill: '#fff' },
      },
    },
    {
      id: 'end',
      shape: 'rect',
      x: 250,
      y: 220,
      width: 100,
      height: 60,
      data: { label: '结束' },
      attrs: {
        body: { fill: '#EF4444', stroke: '#DC2626' },
        label: { text: '结束', fill: '#fff' },
      },
    },
  ],
  edges: [
    {
      id: 'edge1',
      shape: 'flow-edge',
      source: { cell: 'start' },
      target: { cell: 'process1' },
      data: { label: '步骤1' },
      labels: ['步骤1'],
    },
    {
      id: 'edge2',
      shape: 'flow-edge',
      source: { cell: 'process1' },
      target: { cell: 'process2' },
      data: { label: '步骤2' },
      labels: ['步骤2'],
    },
    {
      id: 'edge3',
      shape: 'flow-edge',
      source: { cell: 'process2' },
      target: { cell: 'end' },
      data: { label: '步骤3' },
      labels: ['步骤3'],
    },
  ],
  viewport: {
    tx: 0,
    ty: 0,
    scale: 1,
  },
}

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}

function handleReady(designer, graph) {
  designerRef.value = designer
  addLog('✅ 画布初始化完成')
  addLog('💡 点击"加载示例数据"按钮')
}

/**
 * :after-data-loaded 钩子函数
 * 在 designer.load() 完成后触发
 */
function handleAfterDataLoaded(data: FlowData): void {
  addLog(`🟢 afterDataLoaded 钩子触发`)
  const nodeCount = data.cells?.filter((c: any) => c.shape)?.length || 0
  const edgeCount = data.cells?.filter((c: any) => c.source)?.length || 0
  addLog(`📊 节点数量: ${nodeCount}`)
  addLog(`🔗 连线数量: ${edgeCount}`)
  addLog(`✅ 数据加载完成，画布已渲染`)

  // 演示：可以在数据加载后执行额外操作
  if (designerRef.value) {
    const graph = designerRef.value.getGraph()
    setTimeout(() => {
      graph.centerContent()
      addLog(`🎯 已自动居中显示`)
    }, 100)
  }
}

function loadData() {
  if (!designerRef.value) {
    addLog('⚠️ 画布尚未初始化')
    return
  }

  addLog(`👆 用户点击"加载示例数据"`)
  addLog(`📥 调用 designer.load()...`)

  // 加载数据
  designerRef.value.load(sampleData)
}

function clearCanvas() {
  if (!designerRef.value) return

  addLog(`👆 用户点击"清空画布"`)
  const graph = designerRef.value.getGraph()
  graph.clearCells()
  addLog(`🗑 画布已清空`)
}
</script>

<style scoped>
.demo-data-loaded {
  display: flex;
  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */
  min-height: 400px; /* 添加：最小高度，非全屏时保持合理尺寸 */
  gap: 16px;
}

.demo-data-loaded__log {
  width: 320px;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-data-loaded__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-data-loaded__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-data-loaded__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-data-loaded__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-data-loaded__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-data-loaded__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-data-loaded__log-item:last-child {
  border-bottom: none;
}

.demo-data-loaded__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
  display: flex;
  flex-direction: column;
}

.demo-data-loaded__controls {
  display: flex;
  gap: 12px;
  padding: 12px;
  background: #fff;
  border-bottom: 1px solid #e8e8e8;
}

.demo-data-loaded__btn {
  padding: 6px 16px;
  font-size: 13px;
  color: #fff;
  background: #1677ff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
}

.demo-data-loaded__btn:hover {
  background: #0958d9;
}
</style>
