export default "<template>\r\n  <div style=\"display: flex; flex-direction: column; gap: 12px;\">\r\n\r\n\r\n    <!-- FlowDesigner -->\r\n    <FlowDesignerLayout\r\n      :node-state-renderers=\"computedNodeRenderers\"\r\n      :edge-state-renderers=\"computedEdgeRenderers\"\r\n      @ready=\"handleReady\"\r\n      style=\"height: 400px; border: 1px solid #e8e8e8; border-radius: 6px;\"\r\n    />\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref, computed } from 'vue'\r\nimport { message } from 'ant-design-vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { NodeStateRendererMap, EdgeStateRendererMap } from '@/components/FlowDesigner/types/render'\r\nimport type { Node, Edge } from '@antv/x6'\r\n\r\nconst useCustomNodeStyles = ref(true)\r\nconst useCustomEdgeStyles = ref(true)\r\nconst addErrorState = ref(true)\r\n\r\nlet designerInstance: FlowDesigner | null = null\r\n\r\n// ─────────────────────────────────────────────────────────────────\r\n// 自定义节点状态渲染器\r\n// ─────────────────────────────────────────────────────────────────\r\nconst customNodeRenderers: NodeStateRendererMap = {\r\n  // 覆盖内置 default 状态\r\n  default: (node: Node) => ({\r\n    apply: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          stroke: '#3b82f6',\r\n          strokeWidth: 2,\r\n          fill: '#dbeafe',\r\n        },\r\n        label: {\r\n          fill: '#1e40af',\r\n          fontWeight: 'normal',\r\n        }\r\n      })\r\n    }\r\n  }),\r\n\r\n  // 覆盖内置 hover 状态\r\n  hover: (node: Node) => ({\r\n    apply: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          stroke: '#8b5cf6',\r\n          strokeWidth: 3,\r\n          fill: '#ede9fe',\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }\r\n          }\r\n        },\r\n        label: {\r\n          fill: '#5b21b6',\r\n          fontWeight: 'bold',\r\n        }\r\n      })\r\n    },\r\n    cleanup: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  }),\r\n\r\n  // 覆盖内置 selected 状态\r\n  selected: (node: Node) => ({\r\n    apply: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          stroke: '#06b6d4',\r\n          strokeWidth: 4,\r\n          fill: '#cffafe',\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }\r\n          }\r\n        },\r\n        label: {\r\n          fill: '#164e63',\r\n          fontWeight: 'bold',\r\n        }\r\n      })\r\n    },\r\n    cleanup: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  }),\r\n\r\n  // 新增自定义 error 状态\r\n  error: (node: Node) => ({\r\n    apply: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          stroke: '#ef4444',\r\n          strokeWidth: 3,\r\n          fill: '#fee2e2',\r\n          strokeDasharray: '5, 5',\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 4, color: 'rgba(239, 68, 68, 0.5)' }\r\n          }\r\n        },\r\n        label: {\r\n          fill: '#991b1b',\r\n          fontWeight: 'bold',\r\n        }\r\n      })\r\n    },\r\n    cleanup: (cell) => {\r\n      cell.setAttrs({\r\n        body: {\r\n          strokeDasharray: '',\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n}\r\n\r\n// ─────────────────────────────────────────────────────────────────\r\n// 自定义连线状态渲染器\r\n// ─────────────────────────────────────────────────────────────────\r\nconst customEdgeRenderers: EdgeStateRendererMap = {\r\n  // 覆盖内置 default 状态\r\n  default: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#9333ea',\r\n          strokeWidth: 2,\r\n          strokeDasharray: '',\r\n        },\r\n      });\r\n      console.log('hhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhhh::', cell.getLabels());\r\n      const labelsOrigin = cell.getLabels()\r\n      if (labelsOrigin && labelsOrigin.length > 0) {\r\n        const originalLabel = labelsOrigin[0]\r\n        // 创建新的 label 对象（必须是新对象才能触发 X6 重新渲染）\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#6b21a8',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fillOpacity: 1,  // 明确恢复文本透明度\r\n            },\r\n            body: {\r\n              fill: '#f3e8ff',\r\n              stroke: '#9333ea',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,     // 明确恢复背景透明度\r\n              strokeOpacity: 1,   // 明确恢复边框透明度\r\n            }\r\n          }\r\n        })\r\n      }\r\n    }\r\n  }),\r\n\r\n  // 覆盖内置 hover 状态\r\n  hover: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#0c9157',\r\n          strokeWidth: 3,\r\n        }\r\n      })\r\n      const labelsOrigin = cell.getLabels()\r\n      if (labelsOrigin && labelsOrigin.length > 0) {\r\n        const originalLabel = labelsOrigin[0]\r\n        console.log('originalLabeloriginalLabel::', originalLabel.attrs?.label?.text);\r\n        // 创建新的 label 对象\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#0c9157',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fillOpacity: 1,  // 恢复文本透明度\r\n            },\r\n            body: {\r\n              fill: '#a4e7e0',\r\n              stroke: '#0c9157',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,     // 恢复背景透明度\r\n              strokeOpacity: 1,   // 恢复边框透明度\r\n            }\r\n          }\r\n        })\r\n      }\r\n    }\r\n  }),\r\n\r\n  // 覆盖内置 selected 状态\r\n  selected: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#06b6d4',\r\n          strokeWidth: 4,\r\n        }\r\n      })\r\n      const labelsOrigin = cell.getLabels()\r\n      if (labelsOrigin && labelsOrigin.length > 0) {\r\n        const originalLabel = labelsOrigin[0]\r\n        // 创建新的 label 对象\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#06b6d4',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fillOpacity: 1,  // 恢复文本透明度\r\n            },\r\n            body: {\r\n              fill: '#d3f5fc',\r\n              stroke: '#06b6d4',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,     // 恢复背景透明度\r\n              strokeOpacity: 1,   // 恢复边框透明度\r\n            }\r\n          }\r\n        })\r\n      }\r\n    }\r\n  }),\r\n\r\n  // 覆盖内置 flowing 状态：绿色流动动画\r\n  flowing: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#10b981',         // 绿色\r\n          strokeWidth: 3,\r\n          strokeDasharray: '10,5',   // 虚线样式\r\n          style: {\r\n            animation: 'fd-flow 1s linear infinite'  // CSS 流动动画\r\n          }\r\n        }\r\n      })\r\n      const labelsOrigin = cell.getLabels()\r\n      if (labelsOrigin && labelsOrigin.length > 0) {\r\n        const originalLabel = labelsOrigin[0]\r\n        console.log('originalLabeloriginalLabeloriginalLabel', originalLabel);\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#065f46',\r\n              text: originalLabel.attrs?.label?.text || '',  // 保持原有文字\r\n              fontStyle: 'italic',\r\n              fillOpacity: 1,\r\n            },\r\n            body: {\r\n              fill: '#d1fae5',\r\n              stroke: '#10b981',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,\r\n              strokeOpacity: 1,\r\n            }\r\n          }\r\n        })\r\n      }\r\n    },\r\n    cleanup: (cell) => {\r\n      // 清除流动动画\r\n      cell.setAttrs({\r\n        line: {\r\n          strokeDasharray: '',\r\n          style: {\r\n            animation: 'none'\r\n          }\r\n        }\r\n      })\r\n    }\r\n  }),\r\n}\r\n\r\n// ─────────────────────────────────────────────────────────────────\r\n// 根据开关动态计算要使用的渲染器\r\n// ─────────────────────────────────────────────────────────────────\r\nconst computedNodeRenderers = computed<NodeStateRendererMap | undefined>(() => {\r\n  if (!useCustomNodeStyles.value && !addErrorState.value) {\r\n    return undefined // 使用内置样式\r\n  }\r\n\r\n  const renderers: NodeStateRendererMap = {}\r\n\r\n  if (useCustomNodeStyles.value) {\r\n    renderers.default = customNodeRenderers.default\r\n    renderers.hover = customNodeRenderers.hover\r\n    renderers.selected = customNodeRenderers.selected\r\n  }\r\n\r\n  if (addErrorState.value) {\r\n    renderers.error = customNodeRenderers.error\r\n  }\r\n\r\n  return renderers\r\n})\r\n\r\nconst computedEdgeRenderers = computed<EdgeStateRendererMap | undefined>(() => {\r\n  if (!useCustomEdgeStyles.value) {\r\n    return undefined // 使用内置样式\r\n  }\r\n\r\n  return customEdgeRenderers\r\n})\r\n\r\n// ─────────────────────────────────────────────────────────────────\r\n// Ready 回调：初始化画布数据\r\n// ─────────────────────────────────────────────────────────────────\r\nfunction handleReady(designer) {\r\n  designerInstance = designer\r\n  const graph = designer.getGraph()\r\n\r\n  // 添加示例节点\r\n  const node1 = graph.addNode({\r\n    x: 100,\r\n    y: 100,\r\n    width: 120,\r\n    height: 60,\r\n    label: '节点 1',\r\n    shape: 'rect',\r\n    attrs: {},\r\n  });\r\n  designer.setNodeState(node1, 'default')\r\n\r\n  const node2 = graph.addNode({\r\n    x: 300,\r\n    y: 100,\r\n    width: 120,\r\n    height: 60,\r\n    label: '节点 2',\r\n    shape: 'rect',\r\n    attrs: {},\r\n  })\r\n  designer.setNodeState(node2, 'default')\r\n\r\n  const node3 = graph.addNode({\r\n    x: 200,\r\n    y: 220,\r\n    width: 120,\r\n    height: 60,\r\n    label: '节点 3',\r\n    shape: 'rect',\r\n    attrs: {},\r\n  })\r\n  designer.setNodeState(node3, 'default')\r\n\r\n  // 添加连线\r\n  const edge1 = graph.addEdge({\r\n    source: node1,\r\n    target: node2,\r\n    shape: 'flow-edge',\r\n    labels: ['连接1'],\r\n  })\r\n  designer.setEdgeState(edge1, 'default')\r\n\r\n  const edge2 = graph.addEdge({\r\n    source: node1,\r\n    target: node3,\r\n    shape: 'flow-edge',\r\n    labels: ['连接2'],\r\n  })\r\n  designer.setEdgeState(edge2, 'default')\r\n\r\n  const edge3 = graph.addEdge({\r\n    source: node2,\r\n    target: node3,\r\n    shape: 'flow-edge',\r\n    labels: ['连接3'],\r\n  })\r\n  designer.setEdgeState(edge3, 'default')\r\n\r\n  message.success('✨ 状态渲染器演示已加载！悬停/点击节点和连线查看效果')\r\n}\r\n\r\n// ─────────────────────────────────────────────────────────────────\r\n// 触发自定义 error 状态\r\n// ─────────────────────────────────────────────────────────────────\r\nfunction triggerErrorState() {\r\n  if (!designerInstance) return\r\n\r\n  const graph = designerInstance.getGraph()\r\n  const nodes = graph.getNodes()\r\n\r\n  if (nodes.length > 0) {\r\n    const firstNode = nodes[0]\r\n\r\n    // 调用 setNodeState 切换到 error 状态\r\n    designerInstance.setNodeState(firstNode, 'error')\r\n\r\n    message.warning('节点 1 已切换到 error 状态（3 秒后恢复）')\r\n\r\n    // 3 秒后恢复到 default 状态\r\n    setTimeout(() => {\r\n      if (designerInstance) {\r\n        designerInstance.setNodeState(firstNode, 'default')\r\n        message.info('节点 1 已恢复到 default 状态')\r\n      }\r\n    }, 3000)\r\n  }\r\n}\r\n</script>\r\n"