 * - 自定义状态：可以添加任意自定义状态（如 processing, error 等）
 *
 * 使用场景：
 * 1. 统一连线视觉风格（覆盖 default）
 * 2. 自定义交互反馈（覆盖 hover/selected）
 * 3. 表示业务状态（新增 processing/error/warning 等）
 */
const edgeStateRenderers: EdgeStateRendererMap = {
  // ─────────────────────────────────────────────────────────────────
  // 覆盖内置状态：default - 默认状态
  // ─────────────────────────────────────────────────────────────────
  default: (edge: Edge) => ({
    apply: (cell) => {
      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → default 状态`)

      cell.attr({
        line: {
          stroke: '#9333ea',          // 紫色连线
          strokeWidth: 2,
          strokeDasharray: '',
        },
      })

      // 更新标签样式
      const labels = cell.getLabels()
      console.log('originalLabeloriginalLabel::', JSON.stringify(labels));
      if (labels && labels.length > 0) {
        const originalLabel = labels[0]
        cell.setLabelAt(0, {
          ...originalLabel,
          attrs: {
            label: {
              fill: '#6b21a8',
              text: originalLabel.attrs?.label?.text || '',
              fillOpacity: 1,
            },
            body: {
              fill: '#f3e8ff',
              stroke: '#9333ea',
              strokeWidth: 1,
              fillOpacity: 1,
              strokeOpacity: 1,
            }
          }
        })
      }
    }
  }),

  // ─────────────────────────────────────────────────────────────────
  // 覆盖内置状态：hover - 鼠标悬停
  // ─────────────────────────────────────────────────────────────────
  hover: (edge: Edge) => ({
    apply: (cell) => {
      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → hover 状态`)

      cell.attr({
        line: {
          stroke: '#10b981',         // 绿色高亮
          strokeWidth: 3,
        }
      })

      const labels = cell.getLabels()
      if (labels && labels.length > 0) {
        const originalLabel = labels[0]
        console.log('originalLabeloriginalLabel::', JSON.stringify(originalLabel));
        cell.setLabelAt(0, {
          ...originalLabel,
          attrs: {
            label: {
              fill: '#065f46',
              text: originalLabel.attrs?.label?.text || '',
              fillOpacity: 1,
            },
            body: {
              fill: '#d1fae5',
              stroke: '#10b981',
              strokeWidth: 2,
              fillOpacity: 1,
              strokeOpacity: 1,
            }
          }
        })
      }
    }
  }),

  // ─────────────────────────────────────────────────────────────────
  // 覆盖内置状态：selected - 选中状态
  // ─────────────────────────────────────────────────────────────────
  selected: (edge: Edge) => ({
    apply: (cell) => {
      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → selected 状态`)

      cell.attr({
        line: {
          stroke: '#06b6d4',         // 青色选中
          strokeWidth: 4,
        }
      })

      const labels = cell.getLabels()
      if (labels && labels.length > 0) {
        const originalLabel = labels[0]
        cell.setLabelAt(0, {
          ...originalLabel,
          attrs: {
            label: {
              fill: '#0e7490',
              text: originalLabel.attrs?.label?.text || '',
              fontWeight: 'bold',
              fillOpacity: 1,
            },
            body: {
              fill: '#cffafe',
              stroke: '#06b6d4',
              strokeWidth: 2,
              fillOpacity: 1,
              strokeOpacity: 1,
            }
          }
        })
      }
    }
  }),

  // ─────────────────────────────────────────────────────────────────
  // 覆盖内置状态：flowing - 流动动画（数据流转）
  // ─────────────────────────────────────────────────────────────────
  flowing: (edge: Edge) => ({
    apply: (cell) => {
      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → flowing 状态（流动动画）`)

      cell.attr({
        line: {
          stroke: '#e7581a',         // 绿色流动
          strokeWidth: 3,
          strokeDasharray: '10,5',   // 虚线样式
          style: {
            animation: 'fd-flow 1s linear infinite'  // CSS 动画
          }
        }
      })

      const labels = cell.getLabels()
      if (labels && labels.length > 0) {
        const originalLabel = labels[0]
        cell.setLabelAt(0, {
          ...originalLabel,
          attrs: {
            label: {
              fill: '#e7581a',
              text: originalLabel.attrs?.label?.text || '',
              fontStyle: 'italic',
              fillOpacity: 1,
            },
            body: {
              fill: '#efd9cf',
              stroke: '#e7581a',
              strokeWidth: 2,
              fillOpacity: 1,
              strokeOpacity: 1,
            }
          }
        })
      }
    },
    cleanup: (cell) => {
      // 清除动画
      cell.attr({
        line: {
          strokeDasharray: '',
          style: { animation: 'none' }
        }
      })
    }
  }),

  // ─────────────────────────────────────────────────────────────────
  // 覆盖内置状态：dimmed - 半透明状态（其他元素高亮时）
  // ─────────────────────────────────────────────────────────────────
  dimmed: (edge: Edge) => ({
    apply: (cell) => {
      cell.attr({
        line: {
          strokeOpacity: 0.66,        // 降低不透明度
        }
      })

      const labels = cell.getLabels()
      if (labels && labels.length > 0) {
        const originalLabel = labels[0];
        cell.setLabelAt(0, {
          ...originalLabel,
          attrs: {
            label: {
              fillOpacity: 0.66,
              text: originalLabel?.attrs?.label?.text??''
            },
            body: {
              fillOpacity: 0.66,
              strokeOpacity: 0.66,
            }
          }
        })
      }
    },
    cleanup: (cell) => {
      // 恢复不透明度
      cell.attr({
        line: {
          strokeOpacity: 1,
        }
      })
    }
  }),
}


</script>


