export default "<template>\r\n  <FlowDesignerLayout\r\n    @ready=\"handleReady\"\r\n  />\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { message } from 'ant-design-vue'\r\n//import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Node } from '@antv/x6'\r\n\r\n/**\r\n * ready 回调：为不同节点类型注册不同的状态处理器\r\n *\r\n * 优先级规则：\r\n *   1. 先查找 node.shape 对应的类型专属处理器\r\n *   2. 找不到时降级到全局处理器\r\n */\r\nfunction handleReady(designer: FlowDesigner) {\r\n  const graph = designer.getGraph()\r\n\r\n  // ========== 全局处理器（兜底，所有未单独注册的 shape 使用）==========\r\n\r\n  designer.registerNodeStateHandler('hover', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#8c8c8c',\r\n          strokeWidth: 2,\r\n          strokeDasharray: '4 4',\r\n        },\r\n        label: { fill: '#595959' }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({\r\n        body: { strokeDasharray: '' }\r\n      })\r\n    }\r\n  })\r\n\r\n  // ========== rect 类型：蓝紫色系 ==========\r\n\r\n  designer.registerNodeStateHandlerForType('rect', 'default', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: { stroke: '#3b82f6', strokeWidth: 2, fill: '#dbeafe' },\r\n        label: { fill: '#1e40af', fontWeight: 'normal' }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerNodeStateHandlerForType('rect', 'hover', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#8b5cf6', strokeWidth: 3, fill: '#ede9fe',\r\n          filter: { name: 'dropShadow', args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139,92,246,0.4)' } }\r\n        },\r\n        label: { fill: '#5b21b6', fontWeight: 'bold' }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({ body: { filter: null } })\r\n    }\r\n  })\r\n\r\n  designer.registerNodeStateHandlerForType('rect', 'selected', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#06b6d4', strokeWidth: 4, fill: '#cffafe',\r\n          filter: { name: 'dropShadow', args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6,182,212,0.6)' } }\r\n        },\r\n        label: { fill: '#164e63', fontWeight: 'bold', fontSize: 14 }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({ body: { filter: null } })\r\n    }\r\n  })\r\n\r\n  designer.registerNodeStateHandlerForType('rect', 'error', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#ef4444', strokeWidth: 4, fill: '#fee2e2',\r\n          filter: { name: 'dropShadow', args: { dx: 0, dy: 2, blur: 8, color: 'rgba(239,68,68,0.5)' } }\r\n        },\r\n        label: { fill: '#991b1b', fontWeight: 'bold' }\r\n      })\r\n      const data = node.getData() || {}\r\n      node.setData({ ...data, hasError: true, errorMessage: '节点验证失败' })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({ body: { filter: null } })\r\n      const data = node.getData() || {}\r\n      node.setData({ ...data, hasError: false, errorMessage: undefined })\r\n    }\r\n  })\r\n\r\n  // ========== circle 类型：绿色系 ==========\r\n\r\n  designer.registerNodeStateHandlerForType('circle', 'default', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: { stroke: '#10b981', strokeWidth: 2, fill: '#d1fae5' },\r\n        label: { fill: '#065f46', fontWeight: 'normal' }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerNodeStateHandlerForType('circle', 'hover', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#047857', strokeWidth: 3, fill: '#a7f3d0',\r\n          filter: { name: 'dropShadow', args: { dx: 0, dy: 2, blur: 6, color: 'rgba(16,185,129,0.4)' } }\r\n        },\r\n        label: { fill: '#064e3b', fontWeight: 'bold' }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({ body: { filter: null } })\r\n    }\r\n  })\r\n\r\n  designer.registerNodeStateHandlerForType('circle', 'selected', {\r\n    apply(node) {\r\n      node.setAttrs({\r\n        body: {\r\n          stroke: '#f59e0b', strokeWidth: 4, fill: '#fef3c7',\r\n          filter: { name: 'dropShadow', args: { dx: 0, dy: 0, blur: 8, color: 'rgba(245,158,11,0.5)' } }\r\n        },\r\n        label: { fill: '#92400e', fontWeight: 'bold' }\r\n      })\r\n    },\r\n    cleanup(node) {\r\n      node.setAttrs({ body: { filter: null } })\r\n    }\r\n  })\r\n\r\n  // circle 不注册 error → 使用全局兜底（无专属 error，双击时提示）\r\n\r\n  // ========== ellipse 类型：橙色系 ==========\r\n\r\n  // ellipse 不注册 selected → 悬停时悬停样式，选中时降级到全局 hover 处理器\r\n  // 体现：类型专属 > 全局兜底 的优先级\r\n\r\n  designer.registerNodeStateHandlers('ellipse', {\r\n    default: {\r\n      apply(node) {\r\n        node.setAttrs({\r\n          body: { stroke: '#f97316', strokeWidth: 2, fill: '#ffedd5' },\r\n          label: { fill: '#9a3412', fontWeight: 'normal' }\r\n        })\r\n      }\r\n    },\r\n    hover: {\r\n      apply(node) {\r\n        node.setAttrs({\r\n          body: {\r\n            stroke: '#c2410c', strokeWidth: 3, fill: '#fed7aa',\r\n            strokeDasharray: '8 4',\r\n            filter: { name: 'dropShadow', args: { dx: 0, dy: 2, blur: 6, color: 'rgba(249,115,22,0.4)' } }\r\n          },\r\n          label: { fill: '#7c2d12', fontWeight: 'bold' }\r\n        })\r\n      },\r\n      cleanup(node) {\r\n        node.setAttrs({ body: { filter: null, strokeDasharray: '' } })\r\n      }\r\n    },\r\n    error: {\r\n      apply(node) {\r\n        node.setAttrs({\r\n          body: {\r\n            stroke: '#eab308', strokeWidth: 4, fill: '#fefce8',\r\n            strokeDasharray: '6 3',\r\n            filter: { name: 'dropShadow', args: { dx: 0, dy: 2, blur: 6, color: 'rgba(234,179,8,0.5)' } }\r\n          },\r\n          label: { fill: '#854d0e', fontWeight: 'bold' }\r\n        })\r\n      },\r\n      cleanup(node) {\r\n        node.setAttrs({ body: { filter: null, strokeDasharray: '' } })\r\n      }\r\n    }\r\n  })\r\n\r\n  // ========== 创建演示节点 ==========\r\n\r\n  // rect 节点 × 2\r\n  const node1 = graph.addNode({\r\n    id: 'rect-1', shape: 'rect',\r\n    x: 80, y: 80, width: 150, height: 70,\r\n    label: '矩形 - 悬停试试',\r\n    attrs: { label: { fontSize: 13 } }\r\n  })\r\n  designer.setNodeState(node1, 'default')\r\n\r\n  const node2 = graph.addNode({\r\n    id: 'rect-2', shape: 'rect',\r\n    x: 290, y: 80, width: 150, height: 70,\r\n    label: '矩形 - 点击选中',\r\n    attrs: { label: { fontSize: 13 } }\r\n  })\r\n  designer.setNodeState(node2, 'default')\r\n\r\n  // circle 节点 × 2\r\n  const node3 = graph.addNode({\r\n    id: 'circle-1', shape: 'circle',\r\n    x: 80, y: 220, width: 90, height: 90,\r\n    label: '圆形',\r\n    attrs: { label: { fontSize: 13 } }\r\n  })\r\n  designer.setNodeState(node3, 'default')\r\n\r\n  const node4 = graph.addNode({\r\n    id: 'circle-2', shape: 'circle',\r\n    x: 240, y: 220, width: 90, height: 90,\r\n    label: '圆形',\r\n    attrs: { label: { fontSize: 13 } }\r\n  })\r\n  designer.setNodeState(node4, 'default')\r\n\r\n  // ellipse 节点 × 2\r\n  const node5 = graph.addNode({\r\n    id: 'ellipse-1', shape: 'ellipse',\r\n    x: 500, y: 80, width: 160, height: 80,\r\n    label: '椭圆 - 双击 error',\r\n    attrs: { label: { fontSize: 13 } }\r\n  })\r\n  designer.setNodeState(node5, 'default')\r\n\r\n  const node6 = graph.addNode({\r\n    id: 'ellipse-2', shape: 'ellipse',\r\n    x: 500, y: 220, width: 160, height: 80,\r\n    label: '椭圆 - 无 selected',\r\n    attrs: { label: { fontSize: 13 } }\r\n  })\r\n  designer.setNodeState(node6, 'default')\r\n\r\n  // ========== 添加连线 ==========\r\n\r\n  graph.addEdge({ id: 'edge1', shape: 'flow-edge', source: node1, target: node2, labels: ['流程1'] })\r\n  graph.addEdge({ id: 'edge2', shape: 'flow-edge', source: node2, target: node5, labels: ['流程2'] })\r\n  graph.addEdge({ id: 'edge3', shape: 'flow-edge', source: node1, target: node3, labels: ['流程3'] })\r\n  graph.addEdge({ id: 'edge4', shape: 'flow-edge', source: node3, target: node4, labels: ['流程4'] })\r\n  graph.addEdge({ id: 'edge5', shape: 'flow-edge', source: node5, target: node6, labels: ['流程5'] })\r\n\r\n  graph.centerContent()\r\n\r\n  // ========== 交互：单击循环状态，双击切换 error ==========\r\n\r\n  const stateCycle: Record<string, string[]> = {\r\n    rect:    ['default', 'hover', 'selected'],\r\n    circle:  ['default', 'hover', 'selected'],\r\n    ellipse: ['default', 'hover'],  // ellipse 没有注册 selected，点击只循环 default/hover\r\n  }\r\n  const currentIndex = new Map<string, number>()\r\n\r\n  graph.on('node:click', ({ node }) => {\r\n    const shape = node.shape as string\r\n    const cycle = stateCycle[shape] || ['default']\r\n    const idx = ((currentIndex.get(node.id) ?? 0) + 1) % cycle.length\r\n    currentIndex.set(node.id, idx)\r\n    const nextState = cycle[idx]\r\n    designer.setNodeState(node, nextState)\r\n    message.info(`[${shape}] ${node.id} → ${nextState}`)\r\n  })\r\n\r\n  graph.on('node:dblclick', ({ node }) => {\r\n    const shape = node.shape as string\r\n    const currentState = node.getProp('_state') || 'default'\r\n\r\n    if (currentState === 'error') {\r\n      designer.setNodeState(node, 'default')\r\n      currentIndex.set(node.id, 0)\r\n      message.success(`[${shape}] ${node.id} 已恢复 default`)\r\n      return\r\n    }\r\n\r\n    // 检查该类型是否注册了 error 处理器\r\n    const hasError = designer.getNodeStateHandlerForType(shape, 'error')\r\n    if (hasError) {\r\n      designer.setNodeState(node, 'error')\r\n      message.warning(`[${shape}] ${node.id} → error（双击恢复）`)\r\n    } else {\r\n      message.info(`[${shape}] 未注册 error 状态，无法设置`)\r\n    }\r\n  })\r\n\r\n  console.log('[Demo] 按节点类型注册不同状态处理器示例已加载')\r\n  message.success('rect/circle/ellipse 各有专属状态，单击循环，双击切换 error')\r\n}\r\n</script>\r\n"