<template>
  <div class="demo-slot-properties">
    <!-- 事件日志面板 -->
    <div class="demo-slot-properties__log">
      <div class="demo-slot-properties__log-header">
        <h4>事件日志</h4>
        <button class="demo-slot-properties__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-slot-properties__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-slot-properties__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-slot-properties__canvas">
      <FlowDesignerLayout
        mode="design"
        :before-graph-init="handleBeforeGraphInit"
        @ready="handleReady"
        @selection-change="handleSelectionChange"
      >
        <!-- 自定义属性面板插槽 -->
        <template #properties="{ designer, graph, selectedCells, currentMode, capabilities }">
          <!--selectedCells 获取选中的元素-->
          <div class="custom-properties" :class="{ 'custom-properties--collapsed': isCollapsed }">
            <!-- 收起/展开按钮 -->
            <button
              class="custom-properties__toggle"
              @click="togglePanel"
              :title="isCollapsed ? '展开属性面板' : '收起属性面板'"
            >
              <span class="custom-properties__toggle-icon">
                {{ isCollapsed ? '◀' : '▶' }}
              </span>
            </button>

            <!-- 面板内容 -->
            <div class="custom-properties__content">
              <!-- 头部 -->
              <div class="custom-properties__header">
                <h3 class="custom-properties__title">
                  {{ panelTitle }}
                </h3>
                <span class="custom-properties__desc">
                  {{ panelDesc }}
                </span>
              </div>

            <!-- 画布配置 -->
            <div v-if="selectionType === 'canvas'" class="custom-properties__form">
              <div class="custom-properties__section">
                <div class="custom-properties__section-title">画布设置</div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">画布名称</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    v-model="canvasConfig.name"
                    @input="updateCanvasConfig"
                    placeholder="请输入画布名称"
                  />
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">
                    <input
                      type="checkbox"
                      class="custom-properties__checkbox"
                      v-model="canvasConfig.grid"
                      @change="updateCanvasConfig"
                    />
                    显示网格
                  </label>
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">
                    <input
                      type="checkbox"
                      class="custom-properties__checkbox"
                      v-model="canvasConfig.snapline"
                      @change="updateCanvasConfig"
                    />
                    显示对齐线
                  </label>
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">背景颜色</label>
                  <input
                    type="color"
                    class="custom-properties__color"
                    v-model="canvasConfig.backgroundColor"
                    @input="updateCanvasConfig"
                  />
                </div>
              </div>

              <div class="custom-properties__section">
                <div class="custom-properties__section-title">画布信息</div>
                <div class="custom-properties__info">
                  <div class="custom-properties__info-item">
                    <span class="custom-properties__info-label">节点数量:</span>
                    <span class="custom-properties__info-value">{{ canvasStats.nodeCount }}</span>
                  </div>
                  <div class="custom-properties__info-item">
                    <span class="custom-properties__info-label">连线数量:</span>
                    <span class="custom-properties__info-value">{{ canvasStats.edgeCount }}</span>
                  </div>
                  <div class="custom-properties__info-item">
                    <span class="custom-properties__info-label">缩放比例:</span>
                    <span class="custom-properties__info-value">{{ canvasStats.zoom }}%</span>
                  </div>
                </div>
              </div>
            </div>

            <!-- 节点属性 -->
            <div v-else-if="selectionType === 'node'" class="custom-properties__form">
              <div class="custom-properties__section">
                <div class="custom-properties__section-title">节点信息</div>
                <div class="custom-properties__field">
                  <label class="custom-properties__label">节点 ID</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="selectedNode.id"
                    disabled
                  />
                </div>
                <div class="custom-properties__field">
                  <label class="custom-properties__label">节点类型</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="selectedNode.shape"
                    disabled
                  />
                </div>
              </div>

              <div class="custom-properties__section">
                <div class="custom-properties__section-title">基础属性</div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">节点名称 *</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="selectedNode.label"
                    @input="updateNodeLabel($event.target.value)"
                    placeholder="请输入节点名称"
                  />
                </div>

                <div class="custom-properties__field-row">
                  <div class="custom-properties__field">
                    <label class="custom-properties__label">宽度</label>
                    <input
                      type="number"
                      class="custom-properties__input"
                      :value="selectedNode.size?.width || 0"
                      @input="updateNodeSize('width', Number($event.target.value))"
                      min="50"
                      max="500"
                    />
                  </div>
                  <div class="custom-properties__field">
                    <label class="custom-properties__label">高度</label>
                    <input
                      type="number"
                      class="custom-properties__input"
                      :value="selectedNode.size?.height || 0"
                      @input="updateNodeSize('height', Number($event.target.value))"
                      min="30"
                      max="500"
                    />
                  </div>
                </div>
              </div>

              <div class="custom-properties__section">
                <div class="custom-properties__section-title">业务属性</div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">描述</label>
                  <textarea
                    class="custom-properties__textarea"
                    :value="getNodeData('description')"
                    @input="updateNodeData('description', $event.target.value)"
                    placeholder="请输入节点描述"
                    rows="3"
                  />
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">负责人</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="getNodeData('owner')"
                    @input="updateNodeData('owner', $event.target.value)"
                    placeholder="请输入负责人"
                  />
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">优先级</label>
                  <select
                    class="custom-properties__select"
                    :value="getNodeData('priority')"
                    @change="updateNodeData('priority', $event.target.value)"
                  >
                    <option value="">请选择</option>
                    <option value="high">高</option>
                    <option value="medium">中</option>
                    <option value="low">低</option>
                  </select>
                </div>
              </div>

              <div class="custom-properties__actions">
                <button
                  class="custom-properties__btn custom-properties__btn--danger"
                  @click="deleteNode"
                >
                  删除节点
                </button>
              </div>
            </div>

            <!-- 连线属性 -->
            <div v-else-if="selectionType === 'edge'" class="custom-properties__form">
              <div class="custom-properties__section">
                <div class="custom-properties__section-title">连线信息</div>
                <div class="custom-properties__field">
                  <label class="custom-properties__label">连线 ID</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="selectedEdge.id"
                    disabled
                  />
                </div>
                <div class="custom-properties__field">
                  <label class="custom-properties__label">源节点</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="getEdgeSourceLabel()"
                    disabled
                  />
                </div>
                <div class="custom-properties__field">
                  <label class="custom-properties__label">目标节点</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="getEdgeTargetLabel()"
                    disabled
                  />
                </div>
              </div>

              <div class="custom-properties__section">
                <div class="custom-properties__section-title">基础属性</div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">连线标签</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="getEdgeLabel()"
                    @input="updateEdgeLabel($event.target.value)"
                    placeholder="请输入连线标签"
                  />
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">连线类型</label>
                  <select
                    class="custom-properties__select"
                    :value="getEdgeData('lineType')"
                    @change="updateEdgeData('lineType', $event.target.value)"
                  >
                    <option value="normal">直线</option>
                    <option value="smooth">平滑曲线</option>
                    <option value="rounded">圆角折线</option>
                  </select>
                </div>
              </div>

              <div class="custom-properties__section">
                <div class="custom-properties__section-title">业务属性</div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">条件表达式</label>
                  <input
                    type="text"
                    class="custom-properties__input"
                    :value="getEdgeData('condition')"
                    @input="updateEdgeData('condition', $event.target.value)"
                    placeholder="例如: status === 'approved'"
                  />
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">描述</label>
                  <textarea
                    class="custom-properties__textarea"
                    :value="getEdgeData('description')"
                    @input="updateEdgeData('description', $event.target.value)"
                    placeholder="请输入连线描述"
                    rows="2"
                  />
                </div>

                <div class="custom-properties__field">
                  <label class="custom-properties__label">
                    <input
                      type="checkbox"
                      class="custom-properties__checkbox"
                      :checked="getEdgeData('isDefault')"
                      @change="updateEdgeData('isDefault', $event.target.checked)"
                    />
                    默认路径
                  </label>
                </div>
              </div>

              <div class="custom-properties__actions">
                <button
                  class="custom-properties__btn custom-properties__btn--danger"
                  @click="deleteEdge"
                >
                  删除连线
                </button>
              </div>
            </div>

            <!-- 空状态 -->
            <div v-else class="custom-properties__empty">
              <div class="custom-properties__empty-icon">📝</div>
              <p>请选择画布元素</p>
              <p class="custom-properties__empty-hint">点击节点或连线进行编辑</p>
            </div>
            </div><!-- custom-properties__content 结束 -->
          </div>
        </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from 'vue'
import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import type { FlowDesigner, FlowDesignerOptions } from '@quick-code/x6-flow-designer'
import { Graph, Node, Edge } from '@antv/x6'

const logs = ref<string[]>([])
const selectedNode = ref<Node | null>(null)
const selectedEdge = ref<Edge | null>(null)
const selectionType = ref<'none' | 'node' | 'edge' | 'canvas'>('canvas')
const isCollapsed = ref(false)

let designerInstance: FlowDesigner | null = null
let graphInstance: Graph | null = null

// 画布配置
const canvasConfig = ref({
  name: '流程设计画布',
  grid: true,
  snapline: true,
  backgroundColor: '#ffffff',
})

// 画布统计信息
const canvasStats = ref({
  nodeCount: 0,
  edgeCount: 0,
  zoom: 100,
})

// 面板标题和描述
const panelTitle = computed(() => {
  switch (selectionType.value) {
    case 'node': return '节点属性'
    case 'edge': return '连线属性'
    case 'canvas': return '画布配置'
    default: return '属性编辑'
  }
})

const panelDesc = computed(() => {
  switch (selectionType.value) {
    case 'node': return '编辑节点属性'
    case 'edge': return '编辑连线属性'
    case 'canvas': return '配置画布设置'
    default: return '请选择元素'
  }
})

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}

function togglePanel() {
  isCollapsed.value = !isCollapsed.value
  addLog(isCollapsed.value ? '◀ 收起属性面板' : '▶ 展开属性面板')
}

function handleBeforeGraphInit(options: FlowDesignerOptions) {
  addLog('🔧 初始化自定义节点...')

  Graph.registerNode('custom-circle', {
    inherit: 'circle',
    width: 100,
    height: 100,
    attrs: {
      body: {
        fill: '#5F95FF',
        stroke: '#2563EB',
        strokeWidth: 2,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  }, true)

  Graph.registerNode('custom-rect', {
    inherit: 'rect',
    width: 140,
    height: 70,
    attrs: {
      body: {
        fill: '#47C769',
        stroke: '#27AE60',
        strokeWidth: 2,
        rx: 8,
        ry: 8,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  }, true)

  addLog('✅ 节点注册完成')
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  designerInstance = designer
  graphInstance = graph

  addLog('✅ 画布初始化完成')
  addLog('🎨 自定义属性面板已渲染')

  // 添加初始节点
  const node1 = graph.addNode({
    shape: 'custom-circle',
    x: 100,
    y: 100,
    label: '开始',
    data: {
      description: '流程开始节点',
      owner: '张三',
      priority: 'high',
    },
  })

  const node2 = graph.addNode({
    shape: 'custom-rect',
    x: 300,
    y: 100,
    label: '处理',
    data: {
      description: '执行业务处理',
      owner: '李四',
      priority: 'medium',
    },
  })

  const node3 = graph.addNode({
    shape: 'custom-circle',
    x: 500,
    y: 100,
    label: '结束',
    data: {
      description: '流程结束',
      owner: '王五',
      priority: 'low',
    },
  })

  // 添加连线
  graph.addEdge({
    source: node1,
    target: node2,
    shape: 'flow-edge',
    labels: [{ attrs: { text: { text: '通过' } } }],
    data: {
      lineType: 'normal',
      condition: 'status === "approved"',
      description: '审批通过后的流转',
      isDefault: false,
    },
  })

  graph.addEdge({
    source: node2,
    target: node3,
    shape: 'flow-edge',
    labels: [{ attrs: { text: { text: '完成' } } }],
    data: {
      lineType: 'normal',
      condition: '',
      description: '处理完成后结束',
      isDefault: true,
    },
  })

  addLog('➕ 添加了 3 个节点和 2 条连线')
  addLog('💡 提示: 点击节点、连线或空白区域')

  graph.centerContent()
  updateCanvasStats()

  // 监听画布变化
  graph.on('node:added', updateCanvasStats)
  graph.on('node:removed', updateCanvasStats)
  graph.on('edge:added', updateCanvasStats)
  graph.on('edge:removed', updateCanvasStats)
  graph.on('scale', ({ sx }) => {
    canvasStats.value.zoom = Math.round(sx * 100)
  })
}

function handleSelectionChange(cells: any[]) {
  if (cells.length === 0) {
    // 未选中任何元素，显示画布配置
    selectedNode.value = null
    selectedEdge.value = null
    selectionType.value = 'canvas'
    addLog('📌 显示画布配置')
  } else if (cells.length === 1) {
    if (cells[0].isNode()) {
      // 选中节点
      selectedNode.value = cells[0] as Node
      selectedEdge.value = null
      selectionType.value = 'node'
      addLog(`📌 选中节点: ${selectedNode.value.label || selectedNode.value.id}`)
    } else if (cells[0].isEdge()) {
      // 选中连线
      selectedNode.value = null
      selectedEdge.value = cells[0] as Edge
      selectionType.value = 'edge'
      addLog(`📌 选中连线: ${selectedEdge.value.id}`)
    }
  } else {
    // 多选
    selectedNode.value = null
    selectedEdge.value = null
    selectionType.value = 'none'
    addLog(`📌 选中 ${cells.length} 个元素`)
  }
}

function updateCanvasStats() {
  if (!graphInstance) return
  canvasStats.value.nodeCount = graphInstance.getNodes().length
  canvasStats.value.edgeCount = graphInstance.getEdges().length
}

function updateCanvasConfig() {
  addLog(`⚙️ 更新画布配置: ${canvasConfig.value.name}`)
}

// ==================== 节点操作 ====================

function getNodeData(key: string): any {
  if (!selectedNode.value) return ''
  return selectedNode.value.getData()?.[key] || ''
}

function updateNodeLabel(newLabel: string) {
  if (!selectedNode.value) return
  selectedNode.value.setAttrByPath('label/text', newLabel)
  selectedNode.value.prop('label', newLabel)
  addLog(`✏️ 更新节点名称: ${newLabel}`)
}

function updateNodeSize(dimension: 'width' | 'height', value: number) {
  if (!selectedNode.value) return
  const currentSize = selectedNode.value.getSize()
  const newSize = {
    width: dimension === 'width' ? value : currentSize.width,
    height: dimension === 'height' ? value : currentSize.height,
  }
  selectedNode.value.setSize(newSize)
  addLog(`📏 更新节点尺寸: ${dimension} = ${value}`)
}

function updateNodeData(key: string, value: any) {
  if (!selectedNode.value) return
  const currentData = selectedNode.value.getData() || {}
  selectedNode.value.setData({
    ...currentData,
    [key]: value,
  })
  addLog(`💾 更新节点属性: ${key}`)
}

function deleteNode() {
  if (!selectedNode.value || !graphInstance) return
  const nodeLabel = selectedNode.value.label || selectedNode.value.id
  graphInstance.removeNode(selectedNode.value)
  addLog(`🗑️ 删除节点: ${nodeLabel}`)
}

// ==================== 连线操作 ====================

function getEdgeLabel(): string {
  if (!selectedEdge.value) return ''
  const labels = selectedEdge.value.getLabels()
  if (labels && labels.length > 0) {
    return labels[0].attrs?.text?.text || ''
  }
  return ''
}

function getEdgeSourceLabel(): string {
  if (!selectedEdge.value) return ''
  const sourceNode = selectedEdge.value.getSourceNode()
  return sourceNode?.label || sourceNode?.id || ''
}

function getEdgeTargetLabel(): string {
  if (!selectedEdge.value) return ''
  const targetNode = selectedEdge.value.getTargetNode()
  return targetNode?.label || targetNode?.id || ''
}

function getEdgeData(key: string): any {
  if (!selectedEdge.value) return ''
  return selectedEdge.value.getData()?.[key] || ''
}

function updateEdgeLabel(newLabel: string) {
  if (!selectedEdge.value) return
  designerInstance?.updateEdgeLabelText(selectedEdge.value, newLabel)

  addLog(`✏️ 更新连线标签: ${newLabel}`)
}

function updateEdgeData(key: string, value: any) {
  if (!selectedEdge.value) return
  const currentData = selectedEdge.value.getData() || {}
  selectedEdge.value.setData({
    ...currentData,
    [key]: value,
  })
  addLog(`💾 更新连线属性: ${key}`)
}

function deleteEdge() {
  if (!selectedEdge.value || !graphInstance) return
  graphInstance.removeEdge(selectedEdge.value)
  addLog('🗑️ 删除连线')
}
</script>

<style scoped>
.demo-slot-properties {
  display: flex;
  height: 100%;
  min-height: 600px;
  gap: 16px;
}

.demo-slot-properties__log {
  width: 280px;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-slot-properties__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-slot-properties__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-slot-properties__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-slot-properties__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-slot-properties__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-slot-properties__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-slot-properties__log-item:last-child {
  border-bottom: none;
}

.demo-slot-properties__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
}

/* ==================== 自定义属性面板样式 ==================== */
.custom-properties {
  position: relative;
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 260px;
  background: #f9fafb;
  border-left: 1px solid #e8e8e8;
  transition: width 0.3s ease;
  overflow: visible !important;
}

.custom-properties--collapsed {
  width: 0px;
  min-width: 0px;
  background: transparent;
  border-left: none;
}

.custom-properties--collapsed .custom-properties__content {
  display: none;
}

.custom-properties__toggle {
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 40px;
  height: 80px;
  background: #fff;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  z-index: 100;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
  flex-shrink: 0;
}

.custom-properties--collapsed .custom-properties__toggle {
  left: 0;
  border-radius: 8px 0 0 8px;
  border-right: none;
}

.custom-properties__toggle:hover {
  background: #f0f7ff;
  border-color: #1677ff;
}

.custom-properties__toggle-icon {
  font-size: 16px;
  color: #666;
  transition: color 0.2s;
  font-weight: bold;
}

.custom-properties__toggle:hover .custom-properties__toggle-icon {
  color: #1677ff;
}

.custom-properties__content {
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 100%;
  margin-left: 0;
  transition: margin-left 0.3s ease;
}

.custom-properties--collapsed {
  width: 0;
  margin-right: 40px;
