<template>
  <FlowDesignerLayout
      @ready="handleReady"
  />
</template>

<script setup lang="ts">
import { message } from 'ant-design-vue'
//import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'
import FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'
import type { FlowDesigner } from '@quick-code/x6-flow-designer'
import type { Edge } from '@antv/x6'

/**
 * ready 回调：为不同连线类型注册不同的状态处理器
 *
 * 优先级规则：
 *   1. 先查找 edge.shape 对应的类型专属处理器
 *   2. 找不到时降级到全局处理器
 */
function handleReady(designer: FlowDesigner) {
  const graph = designer.getGraph()

  // ========== 全局处理器（兜底，所有未单独注册的 shape 使用）==========

  designer.registerEdgeStateHandler('default', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#9333ea',
          strokeWidth: 2,
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#6b21a8',
            text: '默认样式',
          },
          rect: {
            fill: '#f3e8ff',
            stroke: '#9333ea',
            strokeWidth: 2,
          }
        }
      })
    }
  })

  designer.registerEdgeStateHandler('hover', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#8c8c8c',
          strokeWidth: 3,
          strokeDasharray: '4 4',
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#595959',
            text: '悬停效果',
          },
          rect: {
            fill: '#f0f0f0',
            stroke: '#8c8c8c',
            strokeWidth: 2,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          strokeDasharray: ''
        }
      })
    }
  })

  designer.registerEdgeStateHandler('selected', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#06b6d4',
          strokeWidth: 3,
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#164e63',
            text: '已选中',
            fontWeight: 'bold',
            fontSize: 14,
          },
          rect: {
            fill: '#cffafe',
            stroke: '#06b6d4',
            strokeWidth: 3,
          }
        }
      })
    }
  })

  // ========== flow-edge 类型：蓝色系（流程线）==========

  designer.registerEdgeStateHandlerForType('flow-edge', 'default', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#3b82f6',
          strokeWidth: 2,
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#1e40af',
            text: '流程线-默认',
          },
          rect: {
            fill: '#dbeafe',
            stroke: '#3b82f6',
            strokeWidth: 2,
          }
        }
      })
    }
  })

  designer.registerEdgeStateHandlerForType('flow-edge', 'hover', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#8b5cf6',
          strokeWidth: 4,
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#5b21b6',
            text: '流程线-悬停',
            fontWeight: 'bold',
          },
          rect: {
            fill: '#ede9fe',
            stroke: '#8b5cf6',
            strokeWidth: 3,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          filter: null
        }
      })
    }
  })

  designer.registerEdgeStateHandlerForType('flow-edge', 'selected', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#06b6d4',
          strokeWidth: 4,
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#164e63',
            text: '流程线-选中',
            fontWeight: 'bold',
            fontSize: 14,
          },
          rect: {
            fill: '#cffafe',
            stroke: '#06b6d4',
            strokeWidth: 4,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          filter: null
        }
      })
    }
  })

  designer.registerEdgeStateHandlerForType('flow-edge', 'flowing', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#ec4899',
          strokeWidth: 3,
          strokeDasharray: '10,5',
          style: {
            animation: 'fd-flow 1s linear infinite'
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#831843',
            text: '流程线-流动中',
            fontStyle: 'italic',
          },
          rect: {
            fill: '#fce7f3',
            stroke: '#ec4899',
            strokeWidth: 2,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          strokeDasharray: 0,
          style: {
            animation: 'none'
          }
        }
      })
    }
  })

  designer.registerEdgeStateHandlerForType('flow-edge', 'flowing', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#ec4899',
          strokeWidth: 3,
          strokeDasharray: '10,5',
          style: {
            animation: 'fd-flow 1s linear infinite'
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#831843',
            text: '流程线-流动中',
            fontStyle: 'italic',
          },
          rect: {
            fill: '#fce7f3',
            stroke: '#ec4899',
            strokeWidth: 2,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          strokeDasharray: 0,
          style: {
            animation: 'none'
          }
        }
      })
    }
  })

  designer.registerEdgeStateHandlerForType('flow-edge', 'dimmed', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#4b5563',
          strokeWidth: 1,
          opacity: 0.3,
          filter: {
            name: 'blur',
            args: { stdDeviation: 1 }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#6b7280',
            text: '已弱化',
            fontStyle: 'italic',
            fontSize: 11,
          },
          rect: {
            fill: '#f3f4f6',
            stroke: '#9ca3af',
            strokeWidth: 1,
            opacity: 0.5,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          opacity: 1,
          filter: null
        }
      })
    }
  })

  // ========== edge 类型：绿色系（标准连线）==========
  // 使用内置的 'edge' 类型作为第二种连线类型示例
  designer.registerEdgeStateHandlerForType('edge', 'hover', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#047857',
          strokeWidth: 4,
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(16, 185, 129, 0.4)' }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#064e3b',
            text: '标准线-悬停',
            fontWeight: 'bold',
          },
          rect: {
            fill: '#a7f3d0',
            stroke: '#047857',
            strokeWidth: 3,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          filter: null
        }
      })
    }
  })

  designer.registerEdgeStateHandlerForType('edge', 'selected', {
    apply(edge) {
      edge.setAttrs({
        line: {
          stroke: '#f59e0b',
          strokeWidth: 4,
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(245, 158, 11, 0.5)' }
          }
        }
      })
      edge.setLabelAt(0, {
        attrs: {
          label: {
            fill: '#92400e',
            text: '标准线-选中',
            fontWeight: 'bold',
            fontSize: 14,
          },
          rect: {
            fill: '#fef3c7',
            stroke: '#f59e0b',
            strokeWidth: 4,
          }
        }
      })
    },
    cleanup(edge) {
      edge.setAttrs({
        line: {
          filter: null
        }
      })
    }
  })

  // edge 不注册 flowing → 使用全局兜底（无专属 flowing）

  // ========== 批量注册：为所有未单独注册的连线提供全局样式 ==========
  // 使用 registerEdgeStateHandlers 批量注册多个状态

  // ========== 创建演示节点 ==========

  const startNode = graph.addNode({
    id: 'start',
    shape: 'rect',
    x: 80,
    y: 120,
    width: 100,
    height: 60,
    label: '开始',
    attrs: {
      body: {
        stroke: '#5b8ff9',
        strokeWidth: 2,
        fill: '#e6f4ff',
      },
      label: {
        fill: '#003a8c',
        fontSize: 14,
      },
    },
  })

  const node1 = graph.addNode({
    id: 'node1',
    shape: 'rect',
    x: 280,
    y: 40,
    width: 100,
    height: 60,
    label: '任务 A',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const node2 = graph.addNode({
    id: 'node2',
    shape: 'rect',
    x: 280,
    y: 140,
    width: 100,
    height: 60,
    label: '任务 B',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const node3 = graph.addNode({
    id: 'node3',
    shape: 'rect',
    x: 480,
    y: 40,
    width: 100,
    height: 60,
    label: '任务 C',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const node4 = graph.addNode({
    id: 'node4',
    shape: 'rect',
    x: 480,
    y: 140,
    width: 100,
    height: 60,
    label: '任务 D',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })

  const endNode = graph.addNode({
    id: 'end',
    shape: 'rect',
    x: 680,
    y: 120,
    width: 100,
    height: 60,
    label: '结束',
    attrs: {
      body: {
        stroke: '#5b8ff9',
        strokeWidth: 2,
        fill: '#e6f4ff',
      },
      label: {
        fill: '#003a8c',
        fontSize: 14,
      },
    },
  })

  // ========== 创建演示连线（展示不同类型的状态）==========

  // flow-edge 类型连线 × 2
  const edge1 = graph.addEdge({
    id: 'edge1',
    shape: 'flow-edge',
    source: startNode,
    target: node1,
    labels: ['流程线'],
  })
  designer.setEdgeState(edge1, 'default')

  const edge2 = graph.addEdge({
    id: 'edge2',
    shape: 'flow-edge',
    source: node1,
    target: node3,
    labels: ['流程线'],
  })
  designer.setEdgeState(edge2, 'default')

  // edge 类型连线 × 2（内置标准连线）
  const edge3 = graph.addEdge({
    id: 'edge3',
    shape: 'edge',  // 使用内置的 'edge' 类型
    source: startNode,
    target: node2,
    labels: ['标准线'],
  })
  designer.setEdgeState(edge3, 'default')

  const edge4 = graph.addEdge({
    id: 'edge4',
    shape: 'edge',
    source: node2,
    target: node4,
    labels: ['标准线'],
  })
  designer.setEdgeState(edge4, 'default')

  const edge5 = graph.addEdge({
    id: 'edge5',
    shape: 'flow-edge',
    source: node3,
    target: endNode,
    labels: ['流程线'],
  })
  designer.setEdgeState(edge5, 'default')

  const edge6 = graph.addEdge({
    id: 'edge6',
    shape: 'edge',
    source: node4,
    target: endNode,
    labels: ['标准线'],
  })
  designer.setEdgeState(edge6, 'default')

  // 居中显示
  graph.centerContent()

  // ========== 交互：点击连线切换状态，双击切换到 flowing（仅 flow-edge 支持）==========

  const stateCycle: Record<string, string[]> = {
    'flow-edge': ['default', 'hover', 'selected', 'flowing'],
    'edge': ['default', 'hover', 'selected'],  // edge 没有 flowing
  }
  const currentIndex = new Map<string, number>()

  graph.on('edge:click', ({ edge }) => {
    const shape = edge.shape as string
    const cycle = stateCycle[shape] || ['default']
    const idx = ((currentIndex.get(edge.id) ?? 0) + 1) % cycle.length
    currentIndex.set(edge.id, idx)
    const nextState = cycle[idx]
    designer.setEdgeState(edge, nextState)
    message.info(`[${shape}] ${edge.id} → ${nextState}`)
  })

  graph.on('edge:dblclick', ({ edge }) => {
    const shape = edge.shape as string
    const currentState = edge.getProp('_state') || 'default'

    if (currentState === 'flowing') {
      designer.setEdgeState(edge, 'default')
      currentIndex.set(edge.id, 0)
      message.success(`[${shape}] ${edge.id} 已恢复 default`)
      return
    }

    // 检查该类型是否注册了 flowing 处理器
    const hasFlowing = designer.getEdgeStateHandlerForType(shape, 'flowing')
    if (hasFlowing) {
      designer.setEdgeState(edge, 'flowing')
      message.warning(`[${shape}] ${edge.id} → flowing（双击恢复）`)
    } else {
      message.info(`[${shape}] 未注册 flowing 状态，无法设置`)
    }
  })

  console.log('[Demo] 按连线类型注册不同状态处理器示例已加载')
  message.success('flow-edge/edge 各有专属状态，单击循环，双击切换 flowing')
}
</script>
