import type { Component } from 'vue'

// ─── 节点形状枚举 ───────────────────────────────────────────────────────────
export type FlowNodeShape =
  | 'start-node'
  | 'end-node'
  | 'approver-node'
  | 'countersign-node'
  | 'orsign-node'
  | 'condition-node'
  | 'parallel-node'
  | 'notify-node'
  | 'x6-node'          // ✅ X6 原生节点
  | 'html-node'        // ✅ HTML 节点
  | 'common-vue-node'  // ✅ 通用 Vue 插槽节点（不固定大小，通过 node-type prop 区分内容）

// ─── 条件分支 ────────────────────────────────────────────────────────────────
export interface ConditionBranch {
  portId: string
  label: string
  condition: string
  isDefault: boolean
}

// ─── 节点业务数据 ─────────────────────────────────────────────────────────────
export interface FlowNodeData {
  label: string
  description?: string
  // 审批类节点
  approverType?: 'user' | 'role' | 'superior' | 'deptHead'
  approvers?: string[]
  roles?: string[]
  commentRequired?: 'required' | 'optional' | 'none'
  allowTransfer?: boolean
  allowAddSign?: boolean
  passPercent?: number
  timeoutEnabled?: boolean
  timeoutHours?: number
  timeoutAction?: 'pass' | 'reject' | 'notify'
  // 条件节点
  branches?: ConditionBranch[]
  // 并行节点
  branchCount?: number
  parallelFinish?: 'all' | 'any'
  // 通知节点
  notifyTitle?: string
  notifyTargetType?: 'user' | 'role' | 'initiator'
  notifyTargets?: string[]
  notifyMethods?: ('message' | 'email' | 'sms')[]
  notifyTemplate?: string
}

// ─── 流程节点 ─────────────────────────────────────────────────────────────────
export interface FlowNode {
  id: string
  shape: FlowNodeShape
  x: number
  y: number
  width: number
  height: number
  data: FlowNodeData
}

// ─── 流程边 ───────────────────────────────────────────────────────────────────
export interface FlowEdge {
  id: string
  source: { cell: string; port: string }
  target: { cell: string; port: string }
  data: {
    condition?: string
    label?: string
  }
}

// ─── 流程元数据 ───────────────────────────────────────────────────────────────
export interface FlowMeta {
  id: string
  name: string
  category: 'leave' | 'expense' | 'purchase' | 'admin' | 'other'
  description: string
  version: string
  status: 'draft' | 'published'
  createdAt: string
  updatedAt: string
  allowRevoke: boolean
  revokeLimit: number
  initiatorScope: {
    type: 'all' | 'dept' | 'role'
    values: string[]
  }
}

// ─── 完整流程数据 ─────────────────────────────────────────────────────────────
// 直接使用 X6 Graph.toJSON() 返回的格式
import type { Cell } from '@antv/x6'

// 使用 X6 内部类型 (从 @antv/x6/es/model/cell 导入)
type CellProperties = any  // X6 的 CellProperties 类型

export interface FlowData {
  cells: CellProperties[]  // X6 标准格式：包含所有节点和连线的完整属性
}

// ─── 节点面板 ─────────────────────────────────────────────────────────────────
export interface NodePaletteItem {
  shape: FlowNodeShape
  label: string
  description: string
  color: string
  icon: Component   // Vue 图标组件
  /** 拖入画布时的初始业务数据（优先级高于 defaultNodeDataMap）*/
  data?: Partial<FlowNodeData> & Record<string, any>
}

export interface NodePaletteGroup {
  key: string
  title: string
  color: string   // 分组标识色，用于 header 左侧竖条
  items: NodePaletteItem[]
}

// ─── Mock 用户/角色 ───────────────────────────────────────────────────────────
export interface MockUser {
  id: string
  name: string
  dept: string
}

export interface MockRole {
  id: string
  name: string
}

// ─── 选中单元格 ───────────────────────────────────────────────────────────────
export interface SelectedCell {
  id: string
  type: 'node' | 'edge'
}

// ─── 画布配置类型 ─────────────────────────────────────────────────────────
// 网格配置
export interface GridConfig {
  visible: boolean
  type: 'dot' | 'mesh'
  size: number
  color: string
  thickness: number
}

// 对齐配置
export interface AlignConfig {
  snaplineEnabled: boolean
  snapToGrid: boolean
  snapRadius: number
}

// 连线配置
export interface ConnectionConfig {
  router: 'manhattan' | 'metro' | 'orth'
  connector: 'rounded' | 'smooth' | 'normal'
  allowBlank: boolean
  allowLoop: boolean
  allowMulti: boolean
  strokeWidth: number
  strokeColor: string
  /**
   * 连线交互层宽度（px）。
   * 用于增大连线的 hover/click 判定范围，视觉上不可见。
   * 推荐值：15-30，越大越容易触发 hover
   */
  interactionWidth: number
    // 标签配置
  label: {
    backgroundColor: string
    borderColor: string
    borderWidth: number
    textColor: string
    fontSize: number
    fontWeight: number
    position: number  // 0-1 之间，表示标签在连线上的位置
    padding: number
    /** 水平内边距（左右），优先级高于 padding */
    paddingX?: number
    /** 垂直内边距（上下），优先级高于 padding。用于补偿 SVG text bbox 含字体行距导致的视觉偏大 */
    paddingY?: number
    /** 背景矩形垂直方向微调（px），正值向下，用于补偿 SVG text baseline 上下不对称 */
    offsetY?: number
    borderRadius: number
    textAnchor: 'start' | 'middle' | 'end'
    textVerticalAnchor: 'top' | 'middle' | 'bottom'
    pointerEvents: 'auto' | 'none' | 'visiblePainted' | 'visibleFill' | 'visibleStroke' | 'visible' | 'painted' | 'fill' | 'stroke' | 'all'
  }
}

// 交互配置
export interface InteractionConfig {
  panning: boolean
  mousewheel: boolean
  rubberband: boolean
  multipleSelection: boolean
  movable: boolean
  resizable: boolean
}

// 高亮配置
export interface HighlightConfig {
  // 节点高亮
  nodeHover: {
    enabled: boolean
    strokeColor: string
    strokeWidth: number
    shadow: boolean
  }
  nodeSelected: {
    enabled: boolean
    strokeColor: string
    strokeWidth: number
    shadow: boolean
  }
  // 连线高亮
  edgeHover: {
    enabled: boolean
    strokeColor: string
    strokeWidth: number
  }
  // 连线悬停重叠优化（hover 时降低重叠连线的透明度）
  edgeHoverOverlap: {
    /** 是否启用重叠连线透明度优化 */
    enabled: boolean
    /** 重叠连线的目标透明度（0-1） */
    opacity: number
    /** 透明度过渡动画时长（ms） */
    transitionDuration: number
    /** 当连线数量超过此值时自动禁用该功能（性能保护），0 或 undefined 表示不限制 */
    disableWhenEdgeCountExceeds?: number
  }
  edgeSelected: {
    enabled: boolean
    strokeColor: string
    strokeWidth: number
  }
  // 端口默认样式（静止状态，注册节点时使用）
  portDefault: {
    /** 端口填充颜色 */
    fill: string
    /** 端口描边颜色 */
    stroke: string
    /** 端口圆半径（px）*/
    size: number
    /** 端口描边宽度（px）*/
    strokeWidth: number
  }
  // 端口高亮
  portHover: {
    enabled: boolean
    strokeColor: string
    strokeWidth: string
    fillColor: string
    size: number
  }
    // 磁铁高亮
  magnetAdsorbed: {
    enabled: boolean
    strokeColor: string
    strokeWidth: number
  }
  // 可用锤点高亮
  magnetAvailable: {
    enabled: boolean
    strokeColor: string
    fillColor: string
    strokeWidth: number
  }
  // 节点悬停时出线流动高亮
  nodeHoverOutEdgeFlow: {
    /** 是否开启:鼠标悬停节点时,出线变为蓝色流动线 */
    enabled: boolean
    /** 流动线颜色 */
    strokeColor: string
    /** 流动线宽度(px)*/
    strokeWidth: number
    /** 流动速度(s),值越小越快 */
    duration: number
    /** 当节点数量超过此值时自动禁用该功能(性能保护),0 或 undefined 表示不限制 */
    disableWhenNodeCountExceeds?: number
    /** 当单个节点的出线数量超过此值时不启用流动动画(性能保护),0 或 undefined 表示不限制 */
    disableWhenOutEdgeCountExceeds?: number
  }
}

// 背景配置
export interface BackgroundConfig {
  color: string
  image?: string
  repeat?: 'repeat' | 'no-repeat' | 'watermark'
  opacity?: number
}

// 小地图配置
export interface MinimapConfig {
  enabled: boolean
  width: number
  height: number
  padding: number
}

// 撤销重做配置
export interface HistoryConfig {
  enabled: boolean
  stackSize: number
  ignoreAdd: boolean
  ignoreRemove: boolean
  ignoreChange: boolean
}

// Tooltip 配置
export interface TooltipConfig {
  /** 字体大小（px）*/
  fontSize: number
  /** 字体粗细（CSS font-weight）*/
  fontWeight: number | string
  /** 文字颜色 */
  color: string
  /** 背景颜色（支持 rgba）*/
  backgroundColor: string
  /** 内边距（CSS 格式，如 '6px 12px'）*/
  padding: string
  /** 圆角（px）*/
  borderRadius: number
  /** 阴影（CSS box-shadow）*/
  boxShadow: string
  /** 是否显示箭头 */
  arrowEnabled: boolean
  /** 箭头颜色（应与 backgroundColor 一致）*/
  arrowColor: string
  /** 箭头高度（px）*/
  arrowSize: number
  /** z-index 层级 */
  zIndex: number
  /** 最大宽度（px），undefined 表示不限制 */
  maxWidth?: number
  /** 文本换行方式 */
  whiteSpace: 'nowrap' | 'normal' | 'pre-wrap'
  /** 水平偏移量（px），正值向右，负值向左 */
  offsetX: number
  /** 垂直偏移量（px），正值向下，负值向上 */
  offsetY: number
}

// 画布完整配置
export interface CanvasConfig {
  grid: GridConfig
  align: AlignConfig
  connection: ConnectionConfig
  interaction: InteractionConfig
  highlight: HighlightConfig
  background: BackgroundConfig
  minimap: MinimapConfig
  history: HistoryConfig
  tooltip: TooltipConfig
}

// ─── 设计器模式相关类型 ─────────────────────────────────────────────────────
// 设计器模式
export type DesignerMode =
  | 'design'        // 设计模式：全功能可用
  | 'readonly'      // 只读模式：隐藏左侧节点栏，工具栏部分功能，属性面板只读
  | 'preview'       // 预览模式：仅显示画布，所有面板隐藏

// 水印配置
export interface WatermarkConfig {
  enabled: boolean
  text: string
  opacity: number
  fontSize: number
  color: string
  rotate: number
}

// 各模式的功能权限
export interface ModeCapabilities {
  // UI 显示
  /** 是否允许显示顶部工具栏 */
  showToolbar: boolean
  /** 是否允许显示左侧节点栏 */
  showNodePalette: boolean
  /** 是否允许显示右侧属性栏 */
  showPropertiesPanel: boolean
  /** 是否允许显示右键菜单 */
  showContextMenu: boolean
  /** 是否允许显示节点 tooltip */
  canNodeTooltip: boolean
  /** 是否允许显示连线 tooltip */
  canEdgeTooltip: boolean
  /** 是否显示小地图（minimap） */
  showMinimap: boolean
  /** 是否允许显示搜索框（Ctrl+F） */
  showSearch: boolean

  // 编辑能力
  /** 是否允许添加新节点（通过拖拽节点面板） */
  canAddNode: boolean
  /** 是否允许拖拽节点 */
  canDrag: boolean
  /** 是否允许创建连线 */
  canConnect: boolean
  /** 是否允许删除元素节点&连线 */
  canDelete: boolean
  /** 是否允许复制节点 */
  canCopy: boolean
  /** 是否允许粘贴节点 */
  canPaste: boolean
  /** 是否允许节点成组功能 */
  canGroup: boolean
  /** 节点/连线层级前置 */
  canToFront: boolean
  /** 节点/连线层级后置 */
  canToBack: boolean
  /** 是否允许变形节点（调整大小、旋转） */
  canTransform: boolean

  // 选择能力
  /** 控制多选（multiple）和框选（rubberband） */
  canMultipleSelect: boolean
  /** 与 canMultipleSelect 共同控制全选（Ctrl+A / 右键全选） */
  canSelectAll: boolean

  // 对齐能力
  canAlign: boolean       // 总开关
  canAlignLeft: boolean   // 左对齐
  canAlignRight: boolean  // 右对齐
  canAlignTop: boolean    // 上对齐
  canAlignBottom: boolean // 下对齐

  // 操作能力
  canImport: boolean     // 导入
  canExport: boolean     // 导出
  canUndo: boolean       // 撤销
  canRedo: boolean       // 重做

  // 视图能力
  canZoom: boolean       // 放大缩小
  canPan: boolean        // 拖动画布
  canFitView: boolean    // 适应画布
  canResetView: boolean  // 重置视图

  // 交互反馈能力
  /** 是否允许节点 hover 样式变化（高亮、tooltip、流动动画等） */
  canHoverNode: boolean
  /** 是否允许连线 hover 样式变化（高亮、tooltip 等） */
  canHoverEdge: boolean
  /** 是否允许选中节点 */
  canSelectNode: boolean
  /** 是否允许选中连线 */
  canSelectEdge: boolean
  /** 是否允许点击画布清空选择并还原状态 */
  canSelectCanvas: boolean
}

// ─── 快捷键映射表 ─────────────────────────────────────────────────────────────────────

/**
 * 快捷键动作枚举（所有可重新映射的内置操作）
 */
export enum ShortcutAction {
  /** 撤销 (默认: ctrl+z) */
  UNDO = 'undo',
  /** 重做 (默认: ctrl+shift+z) */
  REDO = 'redo',
  /** 备用重做 (默认: ctrl+y) */
  REDO_ALT = 'redoAlt',
  /** 复制 (默认: ctrl+c) */
  COPY = 'copy',
  /** 粘贴 (默认: ctrl+v) */
  PASTE = 'paste',
  /** 删除 (默认: delete) */
  DELETE = 'delete',
  /** 备用删除 (默认: backspace) */
  DELETE_ALT = 'deleteAlt',
  /** 全选 (默认: ctrl+a) */
  SELECT_ALL = 'selectAll',
  /** 成组 (默认: ctrl+g) */
  GROUP = 'group',
  /** 解散分组 (默认: ctrl+shift+g) */
  UNGROUP = 'ungroup',
  /** 放大 (默认: ctrl+=) */
  ZOOM_IN = 'zoomIn',
  /** 缩小 (默认: ctrl+-) */
  ZOOM_OUT = 'zoomOut',
  /** 适应画布 (默认: ctrl+0) */
  FIT_VIEW = 'fitView',
  /** 重置视图 (默认: ctrl+shift+h) */
  RESET_VIEW = 'resetView',
  /** 保存 (默认: ctrl+s) */
  SAVE = 'save',
  /** 搜索 (默认: ctrl+f) */
  SEARCH = 'search',
}

/**
 * 快捷键键位映射配置
 * 用于重新映射内置操作的快捷键，无需重写逻辑
 * 
 * @example
 * ```typescript
 * shortcutKeys: {
 *   [ShortcutAction.COPY]: 'ctrl+e',      // 将复制改为 Ctrl+E
 *   [ShortcutAction.PASTE]: 'ctrl+shift+v', // 将粘贴改为 Ctrl+Shift+V
 *   [ShortcutAction.DELETE]: null,         // 禁用删除快捷键
 * }
 * ```
 */
export type ShortcutKeyMap = Partial<Record<ShortcutAction, string | null>>

/**
 * 自定义快捷键映射表。键位为 X6 格式（如 'ctrl+s'、'delete'），值为处理函数。
 * 返回 false 将阻止默认行为（防止浏览器默认操作）。
 */
export type ShortcutMap = Record<string, (e: KeyboardEvent) => boolean | void>

/**
 * 完整快捷键配置（同时支持键位映射和自定义处理）
 */
export interface ShortcutConfig {
  /** 
   * 键位映射：将内置操作映射到新快捷键
   * 设置为 null 可禁用该操作的快捷键
   * 
   * @example
   * ```typescript
   * keyMap: {
   *   [ShortcutAction.COPY]: 'ctrl+e',  // 复制改为 Ctrl+E
   *   [ShortcutAction.DELETE]: null,     // 禁用删除
   * }
   * ```
   */
  keyMap?: ShortcutKeyMap
  
  /**
   * 自定义快捷键：完全自定义的处理逻辑
   * 会覆盖内置快捷键（如果键位冲突）
   * 
   * @example
   * ```typescript
   * custom: {
   *   'ctrl+shift+s': (e) => {
   *     console.log('另存为...')
   *     return false
   *   }
   * }
   * ```
   */
  custom?: ShortcutMap
}
