export default "<template>\r\n  <div class=\"demo-node-svg\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-node-svg__log\">\r\n      <div class=\"demo-node-svg__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-node-svg__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-node-svg__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-node-svg__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-node-svg__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        :before-graph-init=\"handleBeforeGraphInit\"\r\n        :node-state-renderers=\"nodeStateRenderers\"\r\n        :edge-state-renderers=\"edgeStateRenderers\"\r\n        @ready=\"handleReady\"\r\n      >\r\n        <!-- 自定义节点面板插槽 -->\r\n        <template #palette=\"{ onStartDrag }\">\r\n          <div class=\"custom-palette\">\r\n            <div class=\"custom-palette__header\">\r\n              <h3 class=\"custom-palette__title\">SVG 节点</h3>\r\n              <span class=\"custom-palette__desc\">三种状态切换</span>\r\n            </div>\r\n\r\n            <div class=\"custom-palette__section\">\r\n              <div class=\"custom-palette__section-title\">带图标的节点</div>\r\n              <div\r\n                v-for=\"nodeType in nodeTypesConfig\"\r\n                :key=\"nodeType.type\"\r\n                class=\"custom-palette__item\"\r\n                @mousedown=\"(e) => handleStartDrag(e, nodeType, onStartDrag)\"\r\n                :style=\"{ background: nodeType.rectFill, borderColor: nodeType.rectStroke}\"\r\n              >\r\n                <div class=\"custom-palette__item-icon\" >\r\n                  <img :src=\"nodeType.icon\" />\r\n                </div>\r\n                <div class=\"custom-palette__item-info\">\r\n                  <div class=\"custom-palette__item-label\" :style=\"{ color: nodeType.textFill}\">{{ nodeType.label }}</div>\r\n                </div>\r\n              </div>\r\n\r\n              <div\r\n                  key=\"svg-condition-node\"\r\n                  class=\"custom-palette__item\"\r\n                  @mousedown=\"(e) => handleStartDrag(e, {\r\n                    type:'svg-condition-node',\r\n                    label:'条件分支',\r\n                    width: 132,\r\n                    height: 72,\r\n                    }, onStartDrag)\"\r\n                  :style=\"{ background: '#ffeed1', borderColor: '#fdc059'}\"\r\n              >\r\n                <div class=\"custom-palette__item-icon\" >\r\n                  <img :src=\"conditionSvg\" />\r\n                </div>\r\n                <div class=\"custom-palette__item-info\">\r\n                  <div class=\"custom-palette__item-label\" :style=\"{ color: '#ffb02a'}\">条件分支</div>\r\n                </div>\r\n              </div>\r\n\r\n            </div>\r\n\r\n            <div class=\"custom-palette__tips\">\r\n              <div class=\"tips-title\">💡 状态说明</div>\r\n              <ul class=\"tips-list\" style=\"margin-bottom: 60px;\">\r\n                <li><strong>节点状态：</strong></li>\r\n                <li>根据不同的节点类型，设置不同的状态的样式</li>\r\n\r\n                <li><strong>连线状态：</strong></li>\r\n                <li>根据不同的连线类型，设置不同的连线状态的样式</li>\r\n              </ul>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport {computed, ref} from 'vue'\r\nimport { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { PortStateRenderers, EdgeStateRendererMap } from '@/components/FlowDesigner/types/render'\r\nimport { Graph, Node, Edge } from '@antv/x6'\r\n\r\n\r\nimport startSvg from \"./icons/start.svg\";\r\nimport startHover from \"./icons/start-hover.svg\";\r\n\r\nimport approvalSvg from \"./icons/approval.svg\";\r\nimport approvalHoverSvg from \"./icons/approval-hover.svg\";\r\n\r\nimport conditionSvg from \"./icons/condition.svg\";\r\nimport conditionHoverSvg from \"./icons/condition-hover.svg\";\r\n\r\nconst logs = ref<string[]>([])\r\n// FlowDesigner 实例引用\r\nconst flowDesigner = ref<FlowDesigner | null>(null)\r\n\r\n// 节点类型配置（包含颜色和 iconPath）\r\ninterface NodeTypeConfig {\r\n  type: string\r\n  label: string\r\n  hint: string\r\n  color: string\r\n  hoverColor: string\r\n  iconPath: string\r\n  width: number\r\n  height: number\r\n}\r\n\r\nconst nodeTypesConfig: any[] = [\r\n  {\r\n    type: 'svg-start-node',\r\n    label: '开始节点',\r\n    classNamePerfix: 'x6',\r\n    width: 120,\r\n    height: 38,\r\n    rectStroke: '#95d375',\r\n    rectStrokeWidth: 1,\r\n    rectFill: '#edf8e7',\r\n    icon: startSvg,\r\n    iconHover: startHover,\r\n    textFill: '#81cb5c'\r\n  },\r\n  {\r\n    type: 'svg-approval-node',\r\n    label: '审批节点',\r\n    classNamePerfix: 'x6',\r\n    width: 120,\r\n    height: 38,\r\n    rectStroke: '#83b3f7',\r\n    rectStrokeWidth: 1,\r\n    rectFill: '#e6eeff',\r\n    icon: approvalSvg,\r\n    iconHover: approvalHoverSvg,\r\n    textFill: '#5d9df7'\r\n  },\r\n]\r\n\r\nconst Ports = {\r\n  groups: {\r\n    top: {\r\n      position: 'top',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'top',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n    right: {\r\n      position: 'right',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'right',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n    bottom: {\r\n      position: 'bottom',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'bottom',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n    left: {\r\n      position: 'left',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'left',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n  },\r\n  items: [\r\n    {\r\n      group: 'top',\r\n      label: {\r\n        position : 'top'\r\n      }\r\n    },\r\n    {\r\n      group: 'right',\r\n      label: {\r\n        position : 'right'\r\n      }\r\n    },\r\n    {\r\n      group: 'bottom',\r\n      label: {\r\n        position : 'bottom'\r\n      }\r\n    },\r\n    {\r\n      group: 'left',\r\n      label: {\r\n        position : 'left'\r\n      }\r\n    },\r\n  ],\r\n}\r\n\r\n\r\n// 手动跟踪节点的选中状态（因为 X6 的 selection 可能有默认行为）\r\nconst selectedNodesMap = new Map<string, boolean>()\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n\r\n\r\n/**\r\n * Graph 初始化前钩子：注册带 SVG icon 的自定义节点\r\n */\r\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\r\n  addLog('🔧 beforeGraphInit: 开始注册 SVG 节点')\r\n\r\n  // 遍历配置，注册所有节点\r\n  nodeTypesConfig.forEach((config) => {\r\n    Graph.registerNode(\r\n        config.type,\r\n        {\r\n          inherit: 'rect',\r\n          width: config.width,\r\n          height: config.height,\r\n          markup: [\r\n            {\r\n              tagName: 'rect', // 标签名称\r\n              selector: 'body', // 选择器\r\n            },\r\n            {\r\n              tagName: 'path', // 标签名称\r\n              selector: 'icon', // 选择器\r\n            },\r\n            {\r\n              tagName: 'text',\r\n              selector: 'label',\r\n            },\r\n          ],\r\n          attrs: {\r\n            body: {\r\n              stroke: config.rectStroke,\r\n              strokeWidth: config.rectStrokeWidth,\r\n              fill: config.rectFill,\r\n              rx: 10,\r\n              ry: 10,\r\n            },\r\n            icon: {\r\n              fill: config.type == 'svg-start-node'?'#48c02a':'#1d78f4',\r\n              d:config.type == 'svg-start-node'?\r\n                  'M510.9 60.7c-245.6 0-446.7 199.8-446.7 446.7C64.2 753 263.9 954 510.8 954s446.6-199.7 446.6-446.6c0.1-245.6-199.6-446.7-446.5-446.7zM692 525.9l-272.1 157c-10.7 6.2-24-1.5-24-13.9V354.9c0-12.3 13.3-20 24-13.9L692 498.1c10.6 6.2 10.6 21.6 0 27.8z':'M422.399 601.6V493.323c-79.111-34.622-134.4-113.655-134.4-205.323 0-123.711 100.54-224 224-224 123.711 0 224 100.545 224 224 0 91.814-55.379 170.725-134.4 205.313V601.6h201.472c61.925 0 112.128 49.716 112.128 112.003V825.6H108.801V713.598c0-61.855 50.444-111.998 112.126-111.998h201.472zM153.601 870.4h716.793V960H153.6v-89.6z',\r\n              transform: 'translate(12, 9) scale(0.02)'\r\n            },\r\n            text: {\r\n              fontSize: 12,\r\n              fill: config.textFill,\r\n            },\r\n          },\r\n          ports: { ...Ports },\r\n        },\r\n        true,\r\n    );\r\n\r\n    addLog(`✅ 已注册节点: ${config.type} (${config.label})`)\r\n  })  // ✅ 修复：forEach 的回调函数结束\r\n\r\n  Graph.registerNode(\r\n      //'custom-polygon',\r\n      'svg-condition-node',\r\n      {\r\n        inherit: 'polygon',\r\n        width: 132,\r\n        height: 72,\r\n        markup: [\r\n          {\r\n            tagName: 'polygon', // 标签名称\r\n            selector: 'body', // 选择器\r\n          },\r\n          {\r\n            tagName: 'path',\r\n            selector: 'icon',\r\n          },\r\n          {\r\n            tagName: 'text',\r\n            selector: 'label',\r\n          },\r\n        ],\r\n        attrs: {\r\n          body: {\r\n            strokeWidth: 1,\r\n            stroke: '#fdc059',\r\n            fill: '#ffeed1',\r\n            refPoints: '0,20 20,0 40,20 20,40',\r\n          },\r\n          icon: {\r\n            fill: '#ffb02a',\r\n            d: 'M658.944 75.776c26.9312 0 48.64 23.296 48.64 52.0192v207.872c0 28.672-21.7088 51.9168-48.64 51.9168h-97.28v84.48h255.3856c59.1872 0 107.6736 50.2272 109.4144 113.4592v100.864h24.3712a47.104 47.104 0 0 1 34.4064 15.2064c9.1136 9.728 14.2336 22.9888 14.2336 36.7616v155.904c0 28.672-21.76 51.968-48.64 51.968h-145.92c-26.88 0-48.64-23.296-48.64-51.968V738.304c0-28.672 21.76-51.968 48.64-51.968h24.32v-97.4336a12.6976 12.6976 0 0 0-10.752-12.9024l-1.4336-0.1024h-255.3344v110.4384h24.32a47.104 47.104 0 0 1 34.4064 15.2064c9.1136 9.728 14.2336 22.9888 14.2336 36.7616v155.904c0 28.672-21.76 51.968-48.64 51.968h-145.92c-26.88 0-48.64-23.296-48.64-51.968V738.304c0-28.672 21.76-51.968 48.64-51.968h24.32V576H209.0496a12.4928 12.4928 0 0 0-12.032 11.4688l-0.1024 1.536v97.4336h24.32a47.104 47.104 0 0 1 34.4064 15.2064c9.1136 9.728 14.2336 22.9888 14.2336 36.7616v155.904c0 28.672-21.76 51.968-48.64 51.968H75.264c-26.88 0-48.64-23.296-48.64-51.968V738.304c0-28.672 21.76-51.968 48.64-51.968h24.32v-97.4336c0-63.232 47.0528-114.9952 106.1888-116.8384l3.2256-0.1024h255.3856L464.384 387.584l-97.28 0.0512c-26.8288 0-48.64-23.2448-48.64-51.968v-207.872c0-28.672 21.8112-51.9168 48.64-51.9168h291.84z',\r\n            transform: 'translate(54, 9) scale(0.02)'\r\n          },\r\n          text: {\r\n            fontSize: 12,\r\n            fill: '#ffb02a',\r\n            y:8\r\n          },\r\n        },\r\n        ports: {\r\n          ...Ports,\r\n          items: [\r\n            {\r\n              group: 'top',\r\n            },\r\n            {\r\n              group: 'bottom',\r\n            },\r\n          ],\r\n        },\r\n      },\r\n      true,\r\n  );\r\n\r\n  addLog('🎉 所有 SVG 节点注册完成')\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  // 保存 designer 实例\r\n  flowDesigner.value = designer\r\n\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('💡 提示: 悬停查看 hover 效果，点击切换 selected 状态')\r\n\r\n\r\n  // ─── 添加示例节点 ───────────────────────────────────────────────────\r\n  setTimeout(() => {\r\n    const node1 = graph.addNode({\r\n      shape: 'svg-start-node',\r\n      x: 100,\r\n      y: 100,\r\n      label: '开始节点',\r\n    })\r\n\r\n    const node2 = graph.addNode({\r\n      shape: 'svg-approval-node',\r\n      x: 300,\r\n      y: 100,\r\n      label: '审批节点',\r\n    })\r\n\r\n    const node3 = graph.addNode({\r\n      shape: 'svg-condition-node',\r\n      x: 200,\r\n      y: 250,\r\n      label: '条件分支',\r\n    })\r\n\r\n    // ─── 添加连线示例 ───────────────────────────────────────────────────\r\n    // 连接1：node1 的右侧锚点 → node2 的左侧锚点\r\n    graph.addEdge({\r\n      source: { cell: node1, port: node1.getPortAt(1)?.id },  // right port (索引 1)\r\n      target: { cell: node2, port: node2.getPortAt(3)?.id },  // left port (索引 3)\r\n      shape: 'flow-edge',\r\n      labels: ['连接1'],\r\n    })\r\n\r\n    // 连接2：node2 的下侧锚点 → node3 的上侧锚点\r\n    graph.addEdge({\r\n      source: { cell: node2, port: node2.getPortAt(2)?.id },  // bottom port (索引 2)\r\n      target: { cell: node3, port: node3.getPortAt(0)?.id },  // top port (索引 0)\r\n      shape: 'flow-edge',\r\n      labels: ['连接2'],\r\n    })\r\n\r\n    // 连接3：node1 的下侧锚点 → node3 的左侧锚点\r\n    graph.addEdge({\r\n      source: { cell: node1, port: node1.getPortAt(2)?.id },  // bottom port (索引 2)\r\n      target: { cell: node3, port: node3.getPortAt(1)?.id },  // right port (索引 1)\r\n      shape: 'flow-edge',\r\n      labels: ['连接3'],\r\n    })\r\n\r\n    addLog('📦 已添加 3 个示例节点和 3 条连线')\r\n    addLog('🎨 试试悬停和点击节点/连线吧！')\r\n  }, 100)\r\n}\r\n\r\n// ─── portStateRenderers 钩子 ─────────────────────────────────────────────────\r\n\r\n/** portState 对应的中文描述 */\r\nconst portStateLabels: Record<string, string> = {\r\n  'default':     '默认（锚点隐藏/恢复）',\r\n  'node-hover':  '节点悬停（空心锚点显示）',\r\n  'port-hover':  '锚点悬停（实心高亮）',\r\n  'connecting':  '连线中（所有锚点可连）',\r\n  'selected':    '节点选中（锚点显示）',\r\n}\r\n\r\n\r\nfunction handleStartDrag(e: MouseEvent, nodeType: NodeTypeConfig, onStartDrag: any) {\r\n  addLog(`🎯 开始拖拽: ${nodeType.label}`)\r\n\r\n  onStartDrag(e, {\r\n    shape: nodeType.type,\r\n    label: nodeType.label,\r\n    width: nodeType.width,\r\n    height: nodeType.height,\r\n    data: {\r\n      nodeInfo: {\r\n        hint: nodeType.hint,\r\n        color: nodeType.color,\r\n      }\r\n    }\r\n  })\r\n}\r\n\r\n// ════════════════════════════════════════════════════════════════════════════\r\n// 方案B（新）：按节点类型分组的配置 - 集中管理所有节点类型的状态样式\r\n// ════════════════════════════════════════════════════════════════════════════\r\n\r\n/**\r\n * 节点状态样式配置表\r\n *\r\n * 结构：nodeStylesConfig[节点类型][状态名] = 样式对象\r\n *\r\n * 支持的状态：\r\n * - default: 默认状态\r\n * - hover: 鼠标悬停状态\r\n * - selected: 选中状态\r\n * - error: 错误状态（自定义）\r\n */\r\nconst nodeStylesConfig: Record<string, Record<string, any>> = {\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 开始节点 (svg-start-node)\r\n  // ─────────────────────────────────────────────────────────────────\r\n  'svg-start-node': {\r\n    default: {\r\n      body: {\r\n        stroke: '#95d375',\r\n        strokeWidth: 2,\r\n        fill: '#edf8e7',\r\n      },\r\n      label: {\r\n        fill: '#81cb5c',\r\n        fontWeight: 'normal',\r\n      },\r\n      icon: {\r\n        fill:'#48c02a',\r\n        opacity: 1\r\n      },\r\n    },\r\n    hover: {\r\n      body: {\r\n        stroke: '#8b5cf6',\r\n        strokeWidth: 3,\r\n        fill: '#ede9fe',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }\r\n        }\r\n      },\r\n      label: {\r\n        fill: '#5b21b6',\r\n        fontWeight: 'bold',\r\n      },\r\n      icon: {\r\n        opacity: 1,\r\n        fill:'#8b5cf6',\r\n      },\r\n    },\r\n    selected: {\r\n      body: {\r\n        stroke: '#06b6d4',\r\n        strokeWidth: 4,\r\n        fill: '#cffafe',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }\r\n        }\r\n      },\r\n      label: {\r\n        fill: '#0e7490',\r\n        fontWeight: 'bold',\r\n      },\r\n      icon: {\r\n        fill: '#06b6d4',\r\n        opacity: 1\r\n      },\r\n    },\r\n    error: {\r\n      body: {\r\n        stroke: '#ef4444',\r\n        strokeWidth: 4,\r\n        fill: '#fee2e2',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 0, blur: 8, color: 'rgba(239, 68, 68, 0.6)' }\r\n        }\r\n      },\r\n      label: {\r\n        fill: '#991b1b',\r\n        fontWeight: 'bold',\r\n      },\r\n      icon: {\r\n        fill: '#ef4444',\r\n        opacity: 1\r\n      },\r\n    }\r\n  },\r\n\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 审批节点 (svg-approval-node)\r\n  // ─────────────────────────────────────────────────────────────────\r\n  'svg-approval-node': {\r\n    default: {\r\n      body: {\r\n        stroke: '#83b3f7',\r\n        strokeWidth: 2,\r\n        fill: '#e6eeff',\r\n      },\r\n      label: {\r\n        fill: '#5d9df7',\r\n        fontWeight: 'normal',\r\n      },\r\n      icon: {\r\n        fill:'#1d78f4',\r\n        opacity: 1\r\n      },\r\n    },\r\n    hover: {\r\n      body: {\r\n        stroke: '#fdc059',\r\n        strokeWidth: 3,\r\n        fill: '#ffeed1',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 2, blur: 6, color: 'rgba(226,236,152,0.4)' }\r\n        }\r\n      },\r\n      label: {fill: '#ffa100'},\r\n      icon: {fill: '#ffa100',opacity: 1},\r\n    },\r\n    selected: {\r\n      body: {\r\n        stroke: '#2563eb',\r\n        strokeWidth: 4,\r\n        fill: '#bfdbfe',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 0, blur: 8, color: 'rgba(37, 99, 235, 0.6)' }\r\n        }\r\n      },\r\n      label: {\r\n        fill: '#1e40af',\r\n        fontWeight: 'bold',\r\n      },\r\n      icon: {\r\n        fill: '#1d78f4',\r\n        opacity: 1\r\n      },\r\n    },\r\n    // ✅ 审批节点没有 error 状态，不定义即可\r\n  },\r\n\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 条件节点 (svg-condition-node)\r\n  // ─────────────────────────────────────────────────────────────────\r\n  'svg-condition-node': {\r\n    default: {\r\n      body: {\r\n        stroke: '#fdc059',\r\n        strokeWidth: 2,\r\n        fill: '#ffeed1',\r\n      },\r\n      text: {\r\n        fill: '#ffb02a',\r\n        fontWeight: 'normal',\r\n      },\r\n      icon: {\r\n        fill:'#ffa100',\r\n      },\r\n    },\r\n    hover: {\r\n      body: {\r\n        stroke: '#15c71e',\r\n        strokeWidth: 3,\r\n        fill: '#e1f3e4',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 2, blur: 6, color: 'rgba(220,241,218,0.4)' }\r\n        }\r\n      },\r\n      text: {\r\n        fill: '#15c71e',\r\n        fontWeight: 'bold',\r\n      },\r\n      icon: {\r\n        fill:'#15c71e',\r\n      },\r\n    },\r\n    selected: {\r\n      body: {\r\n        stroke: '#d97706',\r\n        strokeWidth: 4,\r\n        fill: '#fde68a',\r\n        filter: {\r\n          name: 'dropShadow',\r\n          args: { dx: 0, dy: 0, blur: 8, color: 'rgba(217, 119, 6, 0.6)' }\r\n        }\r\n      },\r\n      text: {\r\n        fill: '#92400e',\r\n        fontWeight: 'bold',\r\n      },\r\n      icon: {\r\n        fill:'#92400e',\r\n      },\r\n    }\r\n  }\r\n}\r\n\r\n// ════════════════════════════════════════════════════════════════════════════\r\n// 工厂函数：根据样式配置生成状态渲染器\r\n// ════════════════════════════════════════════════════════════════════════════\r\n\r\n/**\r\n * 根据节点类型的样式配置生成状态渲染器\r\n * @param nodeType 节点类型\r\n * @param stylesConfig 样式配置对象\r\n * @returns 状态渲染器映射表\r\n */\r\nfunction createNodeStateRenderersFromConfig(stylesConfig: typeof nodeStylesConfig) {\r\n  const renderers: any = {}\r\n\r\n  Object.entries(stylesConfig).forEach(([nodeType, states]) => {\r\n    renderers[nodeType] = {}\r\n\r\n    Object.entries(states).forEach(([stateName, styles]) => {\r\n      renderers[nodeType][stateName] = {\r\n        apply: (cell: Node, designer?: FlowDesigner) => {\r\n          // 样式应用\r\n          cell.setAttrs(styles)\r\n        },\r\n        cleanup: (cell: Node) => {\r\n          // 根据节点类型清理其他临时效果\r\n          cell.setAttrs({\r\n            body: {\r\n              filter: null,\r\n              strokeDasharray: ''\r\n            }\r\n          })\r\n        }\r\n      }\r\n    })\r\n  })\r\n\r\n  return renderers\r\n}\r\n\r\n// ════════════════════════════════════════════════════════════════════════════\r\n// 生成最终的 nodeStateRenderers（一行代码）\r\n// ════════════════════════════════════════════════════════════════════════════\r\n\r\nconst nodeStateRenderers = createNodeStateRenderersFromConfig(nodeStylesConfig)\r\n\r\n// ════════════════════════════════════════════════════════════════════════════\r\n// 连线状态渲染器（edgeStateRenderers）\r\n// ════════════════════════════════════════════════════════════════════════════\r\n\r\n/**\r\n * 连线状态渲染器配置\r\n *\r\n * 支持覆盖内置状态和添加自定义状态：\r\n * - 内置状态：default, hover, selected, flowing, dimmed\r\n * - 自定义状态：可以添加任意自定义状态（如 processing, error 等）\r\n *\r\n * 使用场景：\r\n * 1. 统一连线视觉风格（覆盖 default）\r\n * 2. 自定义交互反馈（覆盖 hover/selected）\r\n * 3. 表示业务状态（新增 processing/error/warning 等）\r\n */\r\nconst edgeStateRenderers: EdgeStateRendererMap = {\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 覆盖内置状态：default - 默认状态\r\n  // ─────────────────────────────────────────────────────────────────\r\n  default: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → default 状态`)\r\n\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#9333ea',          // 紫色连线\r\n          strokeWidth: 2,\r\n          strokeDasharray: '',\r\n        },\r\n      })\r\n\r\n      // 更新标签样式\r\n      const labels = cell.getLabels()\r\n      console.log('originalLabeloriginalLabel::', JSON.stringify(labels));\r\n      if (labels && labels.length > 0) {\r\n        const originalLabel = labels[0]\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#6b21a8',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fillOpacity: 1,\r\n            },\r\n            body: {\r\n              fill: '#f3e8ff',\r\n              stroke: '#9333ea',\r\n              strokeWidth: 1,\r\n              fillOpacity: 1,\r\n              strokeOpacity: 1,\r\n            }\r\n          }\r\n        })\r\n      }\r\n    }\r\n  }),\r\n\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 覆盖内置状态：hover - 鼠标悬停\r\n  // ─────────────────────────────────────────────────────────────────\r\n  hover: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → hover 状态`)\r\n\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#10b981',         // 绿色高亮\r\n          strokeWidth: 3,\r\n        }\r\n      })\r\n\r\n      const labels = cell.getLabels()\r\n      if (labels && labels.length > 0) {\r\n        const originalLabel = labels[0]\r\n        console.log('originalLabeloriginalLabel::', JSON.stringify(originalLabel));\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#065f46',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fillOpacity: 1,\r\n            },\r\n            body: {\r\n              fill: '#d1fae5',\r\n              stroke: '#10b981',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,\r\n              strokeOpacity: 1,\r\n            }\r\n          }\r\n        })\r\n      }\r\n    }\r\n  }),\r\n\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 覆盖内置状态：selected - 选中状态\r\n  // ─────────────────────────────────────────────────────────────────\r\n  selected: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → selected 状态`)\r\n\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#06b6d4',         // 青色选中\r\n          strokeWidth: 4,\r\n        }\r\n      })\r\n\r\n      const labels = cell.getLabels()\r\n      if (labels && labels.length > 0) {\r\n        const originalLabel = labels[0]\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#0e7490',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fontWeight: 'bold',\r\n              fillOpacity: 1,\r\n            },\r\n            body: {\r\n              fill: '#cffafe',\r\n              stroke: '#06b6d4',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,\r\n              strokeOpacity: 1,\r\n            }\r\n          }\r\n        })\r\n      }\r\n    }\r\n  }),\r\n\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 覆盖内置状态：flowing - 流动动画（数据流转）\r\n  // ─────────────────────────────────────────────────────────────────\r\n  flowing: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      addLog(`🔗 连线 [${cell.id.slice(0, 8)}...] → flowing 状态（流动动画）`)\r\n\r\n      cell.attr({\r\n        line: {\r\n          stroke: '#e7581a',         // 绿色流动\r\n          strokeWidth: 3,\r\n          strokeDasharray: '10,5',   // 虚线样式\r\n          style: {\r\n            animation: 'fd-flow 1s linear infinite'  // CSS 动画\r\n          }\r\n        }\r\n      })\r\n\r\n      const labels = cell.getLabels()\r\n      if (labels && labels.length > 0) {\r\n        const originalLabel = labels[0]\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fill: '#e7581a',\r\n              text: originalLabel.attrs?.label?.text || '',\r\n              fontStyle: 'italic',\r\n              fillOpacity: 1,\r\n            },\r\n            body: {\r\n              fill: '#efd9cf',\r\n              stroke: '#e7581a',\r\n              strokeWidth: 2,\r\n              fillOpacity: 1,\r\n              strokeOpacity: 1,\r\n            }\r\n          }\r\n        })\r\n      }\r\n    },\r\n    cleanup: (cell) => {\r\n      // 清除动画\r\n      cell.attr({\r\n        line: {\r\n          strokeDasharray: '',\r\n          style: { animation: 'none' }\r\n        }\r\n      })\r\n    }\r\n  }),\r\n\r\n  // ─────────────────────────────────────────────────────────────────\r\n  // 覆盖内置状态：dimmed - 半透明状态（其他元素高亮时）\r\n  // ─────────────────────────────────────────────────────────────────\r\n  dimmed: (edge: Edge) => ({\r\n    apply: (cell) => {\r\n      cell.attr({\r\n        line: {\r\n          strokeOpacity: 0.66,        // 降低不透明度\r\n        }\r\n      })\r\n\r\n      const labels = cell.getLabels()\r\n      if (labels && labels.length > 0) {\r\n        const originalLabel = labels[0];\r\n        cell.setLabelAt(0, {\r\n          ...originalLabel,\r\n          attrs: {\r\n            label: {\r\n              fillOpacity: 0.66,\r\n              text: originalLabel?.attrs?.label?.text??''\r\n            },\r\n            body: {\r\n              fillOpacity: 0.66,\r\n              strokeOpacity: 0.66,\r\n            }\r\n          }\r\n        })\r\n      }\r\n    },\r\n    cleanup: (cell) => {\r\n      // 恢复不透明度\r\n      cell.attr({\r\n        line: {\r\n          strokeOpacity: 1,\r\n        }\r\n      })\r\n    }\r\n  }),\r\n}\r\n\r\n\r\n</script>\r\n\r\n\r\n<style scoped>\r\n.demo-node-svg {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 600px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-node-svg__log {\r\n  width: 280px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-node-svg__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-node-svg__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-node-svg__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-node-svg__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-node-svg__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-node-svg__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-node-svg__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-node-svg__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n}\r\n\r\n/* ==================== 自定义节点面板样式 ==================== */\r\n.custom-palette {\r\n  display: flex;\r\n  flex-direction: column;\r\n  height: 100%;\r\n  background: linear-gradient(to bottom, #f9fafb, #ffffff);\r\n  border-right: 1px solid #e8e8e8;\r\n  width: 200px;\r\n}\r\n\r\n.custom-palette__header {\r\n  padding: 16px;\r\n  border-bottom: 2px solid #e8e8e8;\r\n  background: #fff;\r\n}\r\n\r\n.custom-palette__title {\r\n  margin: 0 0 4px 0;\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n}\r\n\r\n.custom-palette__desc {\r\n  font-size: 12px;\r\n  color: #999;\r\n}\r\n\r\n.custom-palette__section {\r\n  padding: 12px;\r\n}\r\n\r\n.custom-palette__section-title {\r\n  font-size: 11px;\r\n  font-weight: 600;\r\n  color: #999;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.06em;\r\n  margin-bottom: 8px;\r\n  padding: 0 4px;\r\n}\r\n\r\n.custom-palette__item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  padding: 10px;\r\n  margin-bottom: 8px;\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 12px;\r\n  cursor: move;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n  width: 160px;\r\n  height: 50px;\r\n}\r\n\r\n.custom-palette__item:hover {\r\n  border-color: #1677ff;\r\n  box-shadow: 0 2px 8px rgba(22, 119, 255, 0.15);\r\n  transform: translateY(-1px);\r\n}\r\n\r\n.custom-palette__item:active {\r\n  transform: translateY(0);\r\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\r\n}\r\n\r\n.custom-palette__item-icon {\r\n  width: 36px;\r\n  height: 36px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  border-radius: 6px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-palette__item-info {\r\n  flex: 1;\r\n  min-width: 0;\r\n}\r\n\r\n.custom-palette__item-label {\r\n  font-size: 13px;\r\n  font-weight: 500;\r\n  color: #333;\r\n  margin-bottom: 2px;\r\n}\r\n\r\n.custom-palette__item-hint {\r\n  font-size: 11px;\r\n  color: #999;\r\n  white-space: nowrap;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n\r\n/* ==================== 交互说明 ==================== */\r\n.custom-palette__tips {\r\n  margin-top: auto;\r\n  padding: 12px;\r\n  background: #fff9e6;\r\n  border-top: 1px solid #ffe58f;\r\n}\r\n\r\n.tips-title {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: #d48806;\r\n  margin-bottom: 8px;\r\n}\r\n\r\n.tips-list {\r\n  margin: 0;\r\n  padding-left: 16px;\r\n  font-size: 11px;\r\n  line-height: 1.8;\r\n  color: #8c8c8c;\r\n}\r\n\r\n.tips-list li {\r\n  margin-bottom: 4px;\r\n}\r\n\r\n.tips-list strong {\r\n  color: #595959;\r\n}\r\n\r\n</style>\r\n\r\n\r\n<!--如果需要简单控制节点样式，需要将此节点样式暴露到全局,适当增加前缀以防止污染-->\r\n<style>\r\n\r\n\r\n</style>\r\n"