export default "<template>\r\n  <FlowDesignerLayout\r\n      @ready=\"handleReady\"\r\n  />\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { message } from 'ant-design-vue'\r\n//import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@quick-code/x6-flow-designer'\r\nimport type { Edge } from '@antv/x6'\r\n\r\n/**\r\n * ready 回调：为不同连线类型注册不同的状态处理器\r\n *\r\n * 优先级规则：\r\n *   1. 先查找 edge.shape 对应的类型专属处理器\r\n *   2. 找不到时降级到全局处理器\r\n */\r\nfunction handleReady(designer: FlowDesigner) {\r\n  const graph = designer.getGraph()\r\n\r\n  // ========== 全局处理器（兜底，所有未单独注册的 shape 使用）==========\r\n\r\n  designer.registerEdgeStateHandler('default', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#9333ea',\r\n          strokeWidth: 2,\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#6b21a8',\r\n            text: '默认样式',\r\n          },\r\n          rect: {\r\n            fill: '#f3e8ff',\r\n            stroke: '#9333ea',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandler('hover', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#8c8c8c',\r\n          strokeWidth: 3,\r\n          strokeDasharray: '4 4',\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#595959',\r\n            text: '悬停效果',\r\n          },\r\n          rect: {\r\n            fill: '#f0f0f0',\r\n            stroke: '#8c8c8c',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          strokeDasharray: ''\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandler('selected', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#06b6d4',\r\n          strokeWidth: 3,\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#164e63',\r\n            text: '已选中',\r\n            fontWeight: 'bold',\r\n            fontSize: 14,\r\n          },\r\n          rect: {\r\n            fill: '#cffafe',\r\n            stroke: '#06b6d4',\r\n            strokeWidth: 3,\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // ========== flow-edge 类型：蓝色系（流程线）==========\r\n\r\n  designer.registerEdgeStateHandlerForType('flow-edge', 'default', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#3b82f6',\r\n          strokeWidth: 2,\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#1e40af',\r\n            text: '流程线-默认',\r\n          },\r\n          rect: {\r\n            fill: '#dbeafe',\r\n            stroke: '#3b82f6',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandlerForType('flow-edge', 'hover', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#8b5cf6',\r\n          strokeWidth: 4,\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#5b21b6',\r\n            text: '流程线-悬停',\r\n            fontWeight: 'bold',\r\n          },\r\n          rect: {\r\n            fill: '#ede9fe',\r\n            stroke: '#8b5cf6',\r\n            strokeWidth: 3,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandlerForType('flow-edge', 'selected', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#06b6d4',\r\n          strokeWidth: 4,\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#164e63',\r\n            text: '流程线-选中',\r\n            fontWeight: 'bold',\r\n            fontSize: 14,\r\n          },\r\n          rect: {\r\n            fill: '#cffafe',\r\n            stroke: '#06b6d4',\r\n            strokeWidth: 4,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandlerForType('flow-edge', 'flowing', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#ec4899',\r\n          strokeWidth: 3,\r\n          strokeDasharray: '10,5',\r\n          style: {\r\n            animation: 'fd-flow 1s linear infinite'\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#831843',\r\n            text: '流程线-流动中',\r\n            fontStyle: 'italic',\r\n          },\r\n          rect: {\r\n            fill: '#fce7f3',\r\n            stroke: '#ec4899',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          strokeDasharray: 0,\r\n          style: {\r\n            animation: 'none'\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandlerForType('flow-edge', 'flowing', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#ec4899',\r\n          strokeWidth: 3,\r\n          strokeDasharray: '10,5',\r\n          style: {\r\n            animation: 'fd-flow 1s linear infinite'\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#831843',\r\n            text: '流程线-流动中',\r\n            fontStyle: 'italic',\r\n          },\r\n          rect: {\r\n            fill: '#fce7f3',\r\n            stroke: '#ec4899',\r\n            strokeWidth: 2,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          strokeDasharray: 0,\r\n          style: {\r\n            animation: 'none'\r\n          }\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandlerForType('flow-edge', 'dimmed', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#4b5563',\r\n          strokeWidth: 1,\r\n          opacity: 0.3,\r\n          filter: {\r\n            name: 'blur',\r\n            args: { stdDeviation: 1 }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#6b7280',\r\n            text: '已弱化',\r\n            fontStyle: 'italic',\r\n            fontSize: 11,\r\n          },\r\n          rect: {\r\n            fill: '#f3f4f6',\r\n            stroke: '#9ca3af',\r\n            strokeWidth: 1,\r\n            opacity: 0.5,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          opacity: 1,\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // ========== edge 类型：绿色系（标准连线）==========\r\n  // 使用内置的 'edge' 类型作为第二种连线类型示例\r\n  designer.registerEdgeStateHandlerForType('edge', 'hover', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#047857',\r\n          strokeWidth: 4,\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(16, 185, 129, 0.4)' }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#064e3b',\r\n            text: '标准线-悬停',\r\n            fontWeight: 'bold',\r\n          },\r\n          rect: {\r\n            fill: '#a7f3d0',\r\n            stroke: '#047857',\r\n            strokeWidth: 3,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  designer.registerEdgeStateHandlerForType('edge', 'selected', {\r\n    apply(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          stroke: '#f59e0b',\r\n          strokeWidth: 4,\r\n          filter: {\r\n            name: 'dropShadow',\r\n            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(245, 158, 11, 0.5)' }\r\n          }\r\n        }\r\n      })\r\n      edge.setLabelAt(0, {\r\n        attrs: {\r\n          label: {\r\n            fill: '#92400e',\r\n            text: '标准线-选中',\r\n            fontWeight: 'bold',\r\n            fontSize: 14,\r\n          },\r\n          rect: {\r\n            fill: '#fef3c7',\r\n            stroke: '#f59e0b',\r\n            strokeWidth: 4,\r\n          }\r\n        }\r\n      })\r\n    },\r\n    cleanup(edge) {\r\n      edge.setAttrs({\r\n        line: {\r\n          filter: null\r\n        }\r\n      })\r\n    }\r\n  })\r\n\r\n  // edge 不注册 flowing → 使用全局兜底（无专属 flowing）\r\n\r\n  // ========== 批量注册：为所有未单独注册的连线提供全局样式 ==========\r\n  // 使用 registerEdgeStateHandlers 批量注册多个状态\r\n\r\n  // ========== 创建演示节点 ==========\r\n\r\n  const startNode = graph.addNode({\r\n    id: 'start',\r\n    shape: 'rect',\r\n    x: 80,\r\n    y: 120,\r\n    width: 100,\r\n    height: 60,\r\n    label: '开始',\r\n    attrs: {\r\n      body: {\r\n        stroke: '#5b8ff9',\r\n        strokeWidth: 2,\r\n        fill: '#e6f4ff',\r\n      },\r\n      label: {\r\n        fill: '#003a8c',\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node1 = graph.addNode({\r\n    id: 'node1',\r\n    shape: 'rect',\r\n    x: 280,\r\n    y: 40,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 A',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node2 = graph.addNode({\r\n    id: 'node2',\r\n    shape: 'rect',\r\n    x: 280,\r\n    y: 140,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 B',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node3 = graph.addNode({\r\n    id: 'node3',\r\n    shape: 'rect',\r\n    x: 480,\r\n    y: 40,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 C',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const node4 = graph.addNode({\r\n    id: 'node4',\r\n    shape: 'rect',\r\n    x: 480,\r\n    y: 140,\r\n    width: 100,\r\n    height: 60,\r\n    label: '任务 D',\r\n    attrs: {\r\n      label: {\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  const endNode = graph.addNode({\r\n    id: 'end',\r\n    shape: 'rect',\r\n    x: 680,\r\n    y: 120,\r\n    width: 100,\r\n    height: 60,\r\n    label: '结束',\r\n    attrs: {\r\n      body: {\r\n        stroke: '#5b8ff9',\r\n        strokeWidth: 2,\r\n        fill: '#e6f4ff',\r\n      },\r\n      label: {\r\n        fill: '#003a8c',\r\n        fontSize: 14,\r\n      },\r\n    },\r\n  })\r\n\r\n  // ========== 创建演示连线（展示不同类型的状态）==========\r\n\r\n  // flow-edge 类型连线 × 2\r\n  const edge1 = graph.addEdge({\r\n    id: 'edge1',\r\n    shape: 'flow-edge',\r\n    source: startNode,\r\n    target: node1,\r\n    labels: ['流程线'],\r\n  })\r\n  designer.setEdgeState(edge1, 'default')\r\n\r\n  const edge2 = graph.addEdge({\r\n    id: 'edge2',\r\n    shape: 'flow-edge',\r\n    source: node1,\r\n    target: node3,\r\n    labels: ['流程线'],\r\n  })\r\n  designer.setEdgeState(edge2, 'default')\r\n\r\n  // edge 类型连线 × 2（内置标准连线）\r\n  const edge3 = graph.addEdge({\r\n    id: 'edge3',\r\n    shape: 'edge',  // 使用内置的 'edge' 类型\r\n    source: startNode,\r\n    target: node2,\r\n    labels: ['标准线'],\r\n  })\r\n  designer.setEdgeState(edge3, 'default')\r\n\r\n  const edge4 = graph.addEdge({\r\n    id: 'edge4',\r\n    shape: 'edge',\r\n    source: node2,\r\n    target: node4,\r\n    labels: ['标准线'],\r\n  })\r\n  designer.setEdgeState(edge4, 'default')\r\n\r\n  const edge5 = graph.addEdge({\r\n    id: 'edge5',\r\n    shape: 'flow-edge',\r\n    source: node3,\r\n    target: endNode,\r\n    labels: ['流程线'],\r\n  })\r\n  designer.setEdgeState(edge5, 'default')\r\n\r\n  const edge6 = graph.addEdge({\r\n    id: 'edge6',\r\n    shape: 'edge',\r\n    source: node4,\r\n    target: endNode,\r\n    labels: ['标准线'],\r\n  })\r\n  designer.setEdgeState(edge6, 'default')\r\n\r\n  // 居中显示\r\n  graph.centerContent()\r\n\r\n  // ========== 交互：点击连线切换状态，双击切换到 flowing（仅 flow-edge 支持）==========\r\n\r\n  const stateCycle: Record<string, string[]> = {\r\n    'flow-edge': ['default', 'hover', 'selected', 'flowing'],\r\n    'edge': ['default', 'hover', 'selected'],  // edge 没有 flowing\r\n  }\r\n  const currentIndex = new Map<string, number>()\r\n\r\n  graph.on('edge:click', ({ edge }) => {\r\n    const shape = edge.shape as string\r\n    const cycle = stateCycle[shape] || ['default']\r\n    const idx = ((currentIndex.get(edge.id) ?? 0) + 1) % cycle.length\r\n    currentIndex.set(edge.id, idx)\r\n    const nextState = cycle[idx]\r\n    designer.setEdgeState(edge, nextState)\r\n    message.info(`[${shape}] ${edge.id} → ${nextState}`)\r\n  })\r\n\r\n  graph.on('edge:dblclick', ({ edge }) => {\r\n    const shape = edge.shape as string\r\n    const currentState = edge.getProp('_state') || 'default'\r\n\r\n    if (currentState === 'flowing') {\r\n      designer.setEdgeState(edge, 'default')\r\n      currentIndex.set(edge.id, 0)\r\n      message.success(`[${shape}] ${edge.id} 已恢复 default`)\r\n      return\r\n    }\r\n\r\n    // 检查该类型是否注册了 flowing 处理器\r\n    const hasFlowing = designer.getEdgeStateHandlerForType(shape, 'flowing')\r\n    if (hasFlowing) {\r\n      designer.setEdgeState(edge, 'flowing')\r\n      message.warning(`[${shape}] ${edge.id} → flowing（双击恢复）`)\r\n    } else {\r\n      message.info(`[${shape}] 未注册 flowing 状态，无法设置`)\r\n    }\r\n  })\r\n\r\n  console.log('[Demo] 按连线类型注册不同状态处理器示例已加载')\r\n  message.success('flow-edge/edge 各有专属状态，单击循环，双击切换 flowing')\r\n}\r\n</script>\r\n"